an Size Minnettardır","href":"/","imageUrl":"/api/media/uploads/1779372215362-5ffd3723ad737721.png","color":"#c40021","order":1,"active":true}],"logoUrl":"https://goalgo-production.up.railway.app/api/media/uploads/1779377710255-194538f212f0acc3.png","hmExtraPages":[{"id":"652cea42-3190-4a54-8452-e6acec8c8128","title":"Sosyal Hizmetler (Dijital Portal)","slug":"sosyal-hizmetler","bodyHtml":"<div class=\"wp-content-placeholder\">WordPress içerik alanı</div>\n\n<style>400;600;700;800&family=Merriweather:ital,wght@0,400;0,700;1,400&display=swap');\n\n:root {\n  --v-red: #8C1A2E; --v-blue: #1A56DB; --v-gold: #C9A84C;\n  --v-dark: #0D1117; --v-text: #1A1F28; --v-border: #EAE6DE;\n}\n\n.sh-portal { font-family: 'Nunito Sans', sans-serif; background: #fafafa; padding-bottom: 80px; }\n\n\n.sh-hero-v3 {\n  background: linear-gradient(135deg, #0D1117, #1C2330);\n  padding: 80px 20px; text-align: center; color: #fff; border-bottom: 4px solid var(--v-gold);\n}\n.sh-hero-v3 h1 { font-family: 'Merriweather', serif; font-size: clamp(2rem, 5vw, 2.8rem); margin-bottom: 15px; }\n.sh-hero-v3 p { max-width: 800px; margin: 0 auto; opacity: 0.8; font-size: 1.1rem; }\n\n.sh-container { max-width: 1300px; margin: 0 auto; padding: 0 20px; }\n\n\n.sh-filter-bar {\n  background: #fff; padding: 25px; border-radius: 12px; box-shadow: 0 10px 30px rgba(0,0,0,0.05);\n  margin: -40px auto 40px; border: 1px solid var(--v-border); display: flex; flex-direction: column; gap: 15px;\n}\n.sh-filter-title { font-weight: 800; font-size: 14px; text-transform: uppercase; color: var(--v-red); letter-spacing: 1px; }\n\n\n.sh-cat-head {\n  display: flex; align-items: center; gap: 15px; margin: 40px 0 25px;\n}\n.sh-cat-head h2 { font-family: 'Merriweather', serif; font-size: 1.6rem; color: var(--v-dark); margin: 0; }\n.sh-cat-head .line { flex-grow: 1; height: 2px; background: var(--v-border); }\n\n\n.sh-matrix { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 20px; }\n\n\n.sh-card-v3 {\n  background: #fff; border: 1px solid var(--v-border); border-radius: 12px; padding: 30px;\n  text-decoration: none !important; transition: 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);\n  display: flex; flex-direction: column; height: 100%;\n}\n.sh-card-v3:hover { transform: translateY(-8px); border-color: var(--v-blue); box-shadow: 0 20px 40px rgba(26, 86, 219, 0.1); }\n\n.sh-type-badge {\n  display: inline-block; padding: 4px 10px; border-radius: 4px; font-size: 10px; font-weight: 800;\n  text-transform: uppercase; margin-bottom: 15px;\n}\n.type-e { background: #EBF5FF; color: #1A56DB; }\n.type-web { background: #F0FDF4; color: #15803D; }\n.type-mob { background: #FDF2F8; color: #BE185D; }\n.type-app { background: #F5F3FF; color: #6D28D9; }\n\n.sh-card-v3 h3 { font-size: 15px; font-weight: 800; color: var(--v-dark); margin-bottom: 12px; line-height: 1.5; height: 45px; overflow: hidden; }\n.sh-card-v3 p { font-size: 13px; color: #4A5568; line-height: 1.6; margin-bottom: 20px; flex-grow: 1; }\n\n.sh-btn-v3 {\n  font-size: 12px; font-weight: 800; color: var(--v-blue); text-transform: uppercase;\n  display: flex; align-items: center; gap: 8px; border-top: 1px solid #f0f0f0; padding-top: 15px;\n}\n\n\n.sh-contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-top: 50px; }\n.sh-contact-box { background: #fff; border: 2px solid var(--v-border); border-radius: 15px; padding: 40px; display: flex; align-items: center; gap: 25px; transition: 0.3s; }\n.sh-contact-box:hover { border-color: var(--v-gold); background: #fff; }\n.sh-c-icon { font-size: 50px; }\n.sh-c-info h4 { margin: 0 0 5px 0; font-family: 'Merriweather', serif; font-size: 1.2rem; }\n.sh-c-info span { font-size: 1.8rem; font-weight: 900; color: var(--v-red); display: block; }\n\n@media (max-width: 768px) { .sh-contact-grid { grid-template-columns: 1fr; } .sh-matrix { grid-template-columns: 1fr; } }</style>\n\n<div class=\"sh-portal\">\n  <section class=\"sh-hero-v3\">\n    <div class=\"sh-container\">\n      <h1>🏛️ Sosyal Hizmetler Kataloğu</h1>\n      <p>İhtiyacınız olan tüm kamu hizmetleri, e-devlet uygulamaları ve sosyal destekler tek bir noktada.</p>\n    </div>\n  </section>\n\n  <div class=\"sh-container\">\n    <div class=\"sh-filter-bar\">\n      <div class=\"sh-filter-title\">Hızlı Erişim Menüsü</div>\n      <div style=\"display:flex; gap:10px; flex-wrap:wrap\">\n        <a href=\"#cat-sehit\" style=\"text-decoration:none; padding:8px 15px; background:var(--v-gray); border-radius:6px; font-size:12px; font-weight:700; color:var(--v-text)\">Şehit & Gazi İşlemleri</a>\n        <a href=\"#cat-aile\" style=\"text-decoration:none; padding:8px 15px; background:var(--v-gray); border-radius:6px; font-size:12px; font-weight:700; color:var(--v-text)\">Aile & Çocuk</a>\n        <a href=\"#cat-kurumsal\" style=\"text-decoration:none; padding:8px 15px; background:var(--v-gray); border-radius:6px; font-size:12px; font-weight:700; color:var(--v-text)\">Kurumsal Uygulamalar</a>\n      </div>\n    </div>\n\n    <div class=\"sh-cat-head\" id=\"cat-sehit\">\n      <h2>Şehit Yakınları ve Gaziler</h2>\n      <div class=\"line\"></div>\n    </div>\n    \n    <div class=\"sh-matrix\">\n      <a href=\"https://www.turkiye.gov.tr/aile-ve-sosyal-hizmetler-sehit-yakinlari-gazi-ve-gazi-yakinlari-atama-kura-sonucu-sorgulama\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-e\">E-Hizmet</span>\n        <h3>3713 Sayılı Kanuna Göre Atama Kurası Sorgulama</h3>\n        <p>Şehit ve gazi yakınları ile gaziler için yapılan atama kura sonuçlarınızı e-devlet üzerinden sorgulayın.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://www.turkiye.gov.tr/aile-ve-sosyal-hizmetler-sehit-yakinlari-gazi-ve-gazi-yakinlari-ucretsiz-seyahat-karti-on-basvurusu\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-e\">E-Hizmet</span>\n        <h3>Ücretsiz Seyahat Kartı Ön Başvurusu</h3>\n        <p>Hak sahibi kendisi, eşi, anne, babası ve çocukları için ücretsiz seyahat kartı başvurusu.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://www.turkiye.gov.tr/aile-ve-sosyal-hizmetler-sehit-yakinlari-gazi-ve-gazi-yakinlari-istihdam-basvuru-sorgulama\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-e\">E-Hizmet</span>\n        <h3>İstihdam Başvuru Sorgulama</h3>\n        <p>Daire Başkanlığı'na intikal eden istihdam başvurularınızın güncel durumunu takip edin.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://apps.apple.com/tr/app/%C5%9Fehit-gazi-mobil/id1527448375\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-mob\">Mobil Uygulama</span>\n        <h3>Şehit Gazi Mobil Uygulaması</h3>\n        <p>QR kod destekli dijital kimlik ve tüm haklara mobil cihazlar üzerinden 7/24 erişim.</p>\n        <div class=\"sh-btn-v3\">Uygulamayı İndir ↗</div>\n      </a>\n    </div>\n\n    <div class=\"sh-cat-head\" id=\"cat-aile\">\n      <h2>Aile, Çocuk ve Sosyal Yardım</h2>\n      <div class=\"line\"></div>\n    </div>\n\n    <div class=\"sh-matrix\">\n      <a href=\"https://ailegenclikfonu.aile.gov.tr/\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-web\">Web Sitesi</span>\n        <h3>Aile ve Gençlik Fonu</h3>\n        <p>Evlenecek gençlere sunulan faizsiz kredi ve eğitim destekleri hakkında bilgi ve başvuru.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://www.turkiye.gov.tr/aile-ve-sosyal-hizmetler-sosyal-ve-ekonomik-destek-hizmeti-on-basvurusu\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-e\">E-Hizmet</span>\n        <h3>Sosyal ve Ekonomik Destek (SED) Başvurusu</h3>\n        <p>Ekonomik yoksunluk içindeki çocukların temel ihtiyaçları için SED ön başvurusu.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://cizgi.aile.gov.tr/\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-web\">Web Sitesi</span>\n        <h3>Aile Çocuk Dergisi</h3>\n        <p>Çocuklar için eğitici ve eğlenceli dijital içerikler sunan güvenli okuma platformu.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://www.turkiye.gov.tr/aile-ve-sosyal-hizmetler-evlat-edinme-on-basvurusu\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-e\">E-Hizmet</span>\n        <h3>Evlat Edinme Ön Başvurusu</h3>\n        <p>Evlat edinme süreçleri ve ilgili mevzuat kapsamında online başvuru hizmeti.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n    </div>\n\n    <div class=\"sh-cat-head\" id=\"cat-kurumsal\">\n      <h2>Kurumsal Bağlantılar ve Eğitim</h2>\n      <div class=\"line\"></div>\n    </div>\n\n    <div class=\"sh-matrix\">\n      <a href=\"https://aileakademi.aile.gov.tr/\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-app\">Kurum Dışı Uygulama</span>\n        <h3>Aile Akademi</h3>\n        <p>Vatandaşlara yönelik eğitimler ve sertifika programları ile aile yapısını güçlendirme.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://ekutuphane.aile.gov.tr/\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-web\">Web Sitesi</span>\n        <h3>E-Kütüphane</h3>\n        <p>Bakanlık bünyesindeki tüm dijital yayınlar, rehberler ve bilimsel çalışmalara erişim.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://erdem.aile.gov.tr/\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-app\">Erişilebilirlik</span>\n        <h3>ERDEM Modülü</h3>\n        <p>Erişilebilirlik Değerlendirme Modülü üzerinden kamu ve özel alan denetimleri.</p>\n        <div class=\"sh-btn-v3\">Hizmete Git ↗</div>\n      </a>\n\n      <a href=\"https://www.aile.tr/btgmd/e-hizmetler-yeni/\" target=\"_blank\" class=\"sh-card-v3\" rel=\"noopener noreferrer\">\n        <span class=\"sh-type-badge type-web\" style=\"background:#000; color:#fff\">Tüm Liste</span>\n        <h3>Bakanlık Hizmet Kataloğu</h3>\n        <p>Tüm e-hizmetlerin, mobil uygulamaların ve web sitelerinin tam listesine ulaşın.</p>\n        <div class=\"sh-btn-v3\">Resmi Listeyi Gör ↗</div>\n      </a>\n    </div>\n\n    <div class=\"sh-contact-grid\">\n      <div class=\"sh-contact-box\">\n        <div class=\"sh-c-icon\">📞</div>\n        <div class=\"sh-c-info\">\n          <h4>Vakıf Danışma Hattı</h4>\n          <span>+90 312 963 07 95</span>\n          <p style=\"margin:5px 0 0; font-size:12px; color:#666\">Hafta içi 09:00 - 18:00 arası</p>\n        </div>\n      </div>\n      <div class=\"sh-contact-box\" style=\"border-color: var(--v-blue);\">\n        <div class=\"sh-c-icon\">🏛️</div>\n        <div class=\"sh-c-info\">\n          <h4>Alo 183 Bakanlık Hattı</h4>\n          <span>7/24 Kesintisiz</span>\n          <p style=\"margin:5px 0 0; font-size:12px; color:#666\">T.C. Aile ve Sosyal Hizmetler Bakanlığı</p>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-sosyal-hizmetler.php","importedAt":"2026-05-22T16:07:28.385Z"},{"id":"4962be26-3e2d-4a70-80aa-68c3615e0b44","title":"Genel Başkan","slug":"baskan","bodyHtml":"<div style=\"font-family: 'Inter', 'Nunito Sans', sans-serif; background-color: #F8FAFC; color: #1E293B; line-height: 1.6; width: 100%; box-sizing: border-box; padding-bottom: 80px;\">\n\n  <link href=\"https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&family=Montserrat:wght@600;700;800&family=Playfair+Display:wght@700;900&display=swap\" rel=\"stylesheet\">\n  <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n\n  <section style=\"position: relative; background: linear-gradient(135deg, rgba(13, 17, 23, 0.96), rgba(140, 26, 46, 0.94)), url('https://images.unsplash.com/photo-1507679799987-c73779587ccf?q=80&w=2000') center/cover no-repeat; padding: 120px 20px; text-align: center; color: #fff; border-bottom: 5px solid #C9A84C; width: 100%; box-sizing: border-box;\">\n    <div style=\"max-width: 1200px; margin: 0 auto; width: 100%;\">\n      <span style=\"display: inline-block; background-color: #C9A84C; color: #0D1117; padding: 6px 20px; border-radius: 50px; font-size: 11px; font-weight: 800; text-transform: uppercase; margin-bottom: 25px; letter-spacing: 2px;\"><i class=\"fa fa-user-tie\"></i> VATAN KAHRAMANLARI</span>\n      <h1 style=\"font-family: 'Playfair Display', serif; font-size: 45px; margin-top: 0; margin-bottom: 25px; font-weight: 900; text-shadow: 2px 2px 10px rgba(0,0,0,0.4); line-height: 1.2;\">Genel Başkan <span style=\"color: #C9A84C; display: block; font-family: 'Montserrat', sans-serif; font-size: 28px; font-weight: 700; margin-top: 10px; letter-spacing: 1px;\">Mustafa ÖZDEMİR</span></h1>\n      <p style=\"max-width: 850px; margin: 0 auto 45px; font-size: 18px; opacity: 0.9; font-weight: 300; line-height: 1.7;\">Vatan Kahramanları Derneği Genel Başkanı Mustafa ÖZDEMİR'in kurumsal mesajları, konuşmaları, basın açıklamaları ve dernek faaliyetleri.</p>\n      \n      <div style=\"display: flex; gap: 20px; justify-content: center; flex-wrap: wrap; width: 100%; max-width: 900px; margin: 0 auto;\">\n        <div style=\"background: rgba(255,255,255,0.06); padding: 22px 30px; border-radius: 16px; border: 1px solid rgba(255,255,255,0.12); flex: 1; min-width: 180px; box-shadow: 0 10px 20px rgba(0,0,0,0.2);\">\n          <div style=\"font-family: 'Montserrat', sans-serif; font-size: 26px; font-weight: 800; color: #C9A84C; margin-bottom: 5px;\">Milli</div>\n          <div style=\"font-size: 12px; opacity: 0.8; font-weight: 500; text-transform: uppercase; letter-spacing: 1px;\">Şuurlu Duruş</div>\n        </div>\n        <div style=\"background: rgba(255,255,255,0.06); padding: 22px 30px; border-radius: 16px; border: 1px solid rgba(255,255,255,0.12); flex: 1; min-width: 180px; box-shadow: 0 10px 20px rgba(0,0,0,0.2);\">\n          <div style=\"font-family: 'Montserrat', sans-serif; font-size: 26px; font-weight: 800; color: #C9A84C; margin-bottom: 5px;\">7/24</div>\n          <div style=\"font-size: 12px; opacity: 0.8; font-weight: 500; text-transform: uppercase; letter-spacing: 1px;\">Vefa ve Destek</div>\n        </div>\n        <div style=\"background: rgba(255,255,255,0.06); padding: 22px 30px; border-radius: 16px; border: 1px solid rgba(255,255,255,0.12); flex: 1; min-width: 180px; box-shadow: 0 10px 20px rgba(0,0,0,0.2);\">\n          <div style=\"font-family: 'Montserrat', sans-serif; font-size: 26px; font-weight: 800; color: #C9A84C; margin-bottom: 5px;\">Ankara</div>\n          <div style=\"font-size: 12px; opacity: 0.8; font-weight: 500; text-transform: uppercase; letter-spacing: 1px;\">Genel Merkez</div>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <div style=\"max-width: 1200px; margin: 60px auto 0; padding: 0 20px; width: 100%; box-sizing: border-box;\">\n    \n    <div style=\"display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 30px; margin-bottom: 60px; width: 100%; box-sizing: border-box;\">\n      \n      <a href=\"https://yekpare.net/tr/vkd/haber/genel-baskanimiz-mustafa-ozdemir?siteId=7\" style=\"text-decoration: none; display: block; background: #fff; border: 1px solid #E2E8F0; border-radius: 20px; overflow: hidden; box-shadow: 0 4px 15px rgba(0,0,0,0.02); transition: transform 0.3s ease;\">\n        <div style=\"height: 8px; background: #8C1A2E; width: 100%;\"></div>\n        <div style=\"padding: 35px 30px;\">\n          <div style=\"background: rgba(140, 26, 46, 0.08); width: 55px; height: 55px; border-radius: 14px; display: flex; align-items: center; justify-content: center; color: #8C1A2E; font-size: 22px; margin-bottom: 25px;\">\n            <i class=\"fa fa-user-check\"></i>\n          </div>\n          <h3 style=\"font-family: 'Montserrat', sans-serif; font-size: 19px; color: #0D1117; margin: 0 0 12px; font-weight: 700;\">Genel Başkanımız</h3>\n          <p style=\"color: #64748B; font-size: 14.5px; margin: 0 0 25px; line-height: 1.6;\">Genel Başkanımız Mustafa ÖZDEMİR'in özgeçmişi, milli meselelerdeki duruşu ve geleceğe yönelik mesajları.</p>\n          <div style=\"display: flex; justify-content: space-between; align-items: center; font-size: 13px; font-weight: 700; color: #8C1A2E; text-transform: uppercase; letter-spacing: 0.5px;\">\n            <span>Başkanı İncele</span> <i class=\"fa fa-arrow-right-long\"></i>\n          </div>\n        </div>\n      </a>\n\n      <a href=\"https://yekpare.net/tr/vkd/kategori/dernegimiz?siteId=7\" style=\"text-decoration: none; display: block; background: #fff; border: 1px solid #E2E8F0; border-radius: 20px; overflow: hidden; box-shadow: 0 4px 15px rgba(0,0,0,0.02); transition: transform 0.3s ease;\">\n        <div style=\"height: 8px; background: #C9A84C; width: 100%;\"></div>\n        <div style=\"padding: 35px 30px;\">\n          <div style=\"background: rgba(201, 168, 76, 0.12); width: 55px; height: 55px; border-radius: 14px; display: flex; align-items: center; justify-content: center; color: #C9A84C; font-size: 22px; margin-bottom: 25px;\">\n            <i class=\"fa fa-users\"></i>\n          </div>\n          <h3 style=\"font-family: 'Montserrat', sans-serif; font-size: 19px; color: #0D1117; margin: 0 0 12px; font-weight: 700;\">Derneğimiz</h3>\n          <p style=\"color: #64748B; font-size: 14.5px; margin: 0 0 25px; line-height: 1.6;\">Vatan Kahramanları Derneği'nin kuruluş amaçları, tüzüğü, vizyonu ve şehit yakınları ile gazilerimize yönelik tüm çalışmaları.</p>\n          <div style=\"display: flex; justify-content: space-between; align-items: center; font-size: 13px; font-weight: 700; color: #C9A84C; text-transform: uppercase; letter-spacing: 0.5px;\">\n            <span>Derneğe Git</span> <i class=\"fa fa-arrow-right-long\"></i>\n          </div>\n        </div>\n      </a>\n\n      <a href=\"https://yekpare.net/tr/vkd/iletisim\" style=\"text-decoration: none; display: block; background: #fff; border: 1px solid #E2E8F0; border-radius: 20px; overflow: hidden; box-shadow: 0 4px 15px rgba(0,0,0,0.02); transition: transform 0.3s ease;\">\n        <div style=\"height: 8px; background: #0D1117; width: 100%;\"></div>\n        <div style=\"padding: 35px 30px;\">\n          <div style=\"background: rgba(13, 17, 23, 0.06); width: 55px; height: 55px; border-radius: 14px; display: flex; align-items: center; justify-content: center; color: #0D1117; font-size: 22px; margin-bottom: 25px;\">\n            <i class=\"fa fa-address-book\"></i>\n          </div>\n          <h3 style=\"font-family: 'Montserrat', sans-serif; font-size: 19px; color: #0D1117; margin: 0 0 12px; font-weight: 700;\">İletişim Bilgileri</h3>\n          <p style=\"color: #64748B; font-size: 14.5px; margin: 0 0 25px; line-height: 1.6;\">Genel Merkezimizle irtibata geçmek, projelerimize destek sağlamak veya bilgi edinmek için resmi kanallarımız.</p>\n          <div style=\"display: flex; justify-content: space-between; align-items: center; font-size: 13px; font-weight: 700; color: #0D1117; text-transform: uppercase; letter-spacing: 0.5px;\">\n            <span>İletişime Geç</span> <i class=\"fa fa-arrow-right-long\"></i>\n          </div>\n        </div>\n      </a>\n\n    </div>\n\n    <div style=\"background: linear-gradient(135deg, #0D1117, #1E293B); border-left: 6px solid #C9A84C; border-radius: 16px; padding: 45px 40px; margin-bottom: 60px; box-sizing: border-box; box-shadow: 0 10px 25px rgba(0,0,0,0.05); text-align: center;\">\n      <p style=\"font-family: 'Playfair Display', serif; font-style: italic; font-size: 24px; color: #fff; margin-top: 0; margin-bottom: 15px; font-weight: 700; line-height: 1.4;\">\"Vatan uğruna can veren kahramanlarımızın hatırasını yaşatmak en kutlu vazifemizdir.\"</p>\n      <div style=\"font-family: 'Montserrat', sans-serif; font-size: 14px; color: #C9A84C; font-weight: 700; text-transform: uppercase; letter-spacing: 1px;\">— Mustafa ÖZDEMİR, Vatan Kahramanları Derneği Genel Başkanı</div>\n    </div>\n\n    <div style=\"margin-bottom: 40px; border-left: 5px solid #8C1A2E; padding-left: 18px; display: flex; justify-content: space-between; align-items: flex-end; flex-wrap: wrap; gap: 20px;\">\n      <div>\n        <h3 style=\"font-family: 'Montserrat', sans-serif; font-weight: 800; color: #0D1117; margin: 0; font-size: 24px; text-transform: uppercase; letter-spacing: 0.5px;\">Genel Başkan Yazıları</h3>\n        <p style=\"color: #64748B; margin: 5px 0 0; font-size: 14px;\">Milli şuur, vatanseverlik ve dernek vizyonuna ait en son kaleme alınan makaleler.</p>\n      </div>\n      <a href=\"https://yekpare.net/tr/vkd/kategori/dernegimiz?siteId=7\" style=\"color: #8C1A2E; font-weight: 700; font-size: 14px; text-decoration: none; text-transform: uppercase; letter-spacing: 0.5px;\">Tümünü Gör <i class=\"fa fa-arrow-right-long\" style=\"margin-left: 5px;\"></i></a>\n    </div>\n\n    <div style=\"display: grid; grid-template-columns: repeat(auto-fit, minmax(340px, 1fr)); gap: 30px; margin-bottom: 60px; width: 100%; box-sizing: border-box;\">\n      \n      <div style=\"background: #fff; border-radius: 16px; border: 1px solid #E2E8F0; overflow: hidden; box-shadow: 0 4px 15px rgba(0,0,0,0.02); display: flex; flex-direction: column;\">\n        <div style=\"position: relative; height: 210px; background: #0D1117 url('https://images.unsplash.com/photo-1457369804613-52c61a468e7d?q=80&w=1000') center/cover;\">\n          <span style=\"position: absolute; top: 15px; left: 15px; background: #8C1A2E; color: #fff; font-size: 11px; font-weight: 700; padding: 5px 12px; border-radius: 4px; text-transform: uppercase; letter-spacing: 0.5px;\">Birlik ve Beraberlik</span>\n        </div>\n        <div style=\"padding: 25px; flex: 1; display: flex; flex-direction: column; justify-content: space-between;\">\n          <div>\n            <h4 style=\"margin: 0 0 12px; font-family: 'Montserrat', sans-serif; font-size: 17px; font-weight: 700; color: #0D1117; line-height: 1.45;\">Kahramanlarımızın Emanetine Sahip Çıkmak</h4>\n            <p style=\"margin: 0 0 20px; font-size: 14px; color: #64748B; line-height: 1.6; text-align: justify;\">Gelişen dünyada ve zorlu coğrafyamızda köklerimizden kopmadan, şehit ve gazi ailelerimizin toplumsal yapımızdaki sarsılmaz yerini koruma kararlılığımız üzerine...</p>\n          </div>\n          <div style=\"display: flex; justify-content: space-between; align-items: center; font-size: 12px; color: #94A3B8; border-top: 1px solid #F1F5F9; padding-top: 15px;\">\n            <span><i class=\"fa fa-calendar-days\" style=\"margin-right: 5px;\"></i> Başyazı</span>\n            <a href=\"https://yekpare.net/tr/vkd/haber/genel-baskanimiz-mustafa-ozdemir?siteId=7\" style=\"color: #8C1A2E; font-weight: 600; text-decoration: none;\">Devamını Oku <i class=\"fa fa-chevron-right\" style=\"font-size: 10px; margin-left: 2px;\"></i></a>\n          </div>\n        </div>\n      </div>\n\n      <div style=\"background: #fff; border-radius: 16px; border: 1px solid #E2E8F0; overflow: hidden; box-shadow: 0 4px 15px rgba(0,0,0,0.02); display: flex; flex-direction: column;\">\n        <div style=\"position: relative; height: 210px; background: #0D1117 url('https://images.unsplash.com/photo-1516979187457-637abb4f9353?q=80&w=1000') center/cover;\">\n          <span style=\"position: absolute; top: 15px; left: 15px; background: #C9A84C; color: #0D1117; font-size: 11px; font-weight: 800; padding: 5px 12px; border-radius: 4px; text-transform: uppercase; letter-spacing: 0.5px;\">Vefa Projeleri</span>\n        </div>\n        <div style=\"padding: 25px; flex: 1; display: flex; flex-direction: column; justify-content: space-between;\">\n          <div>\n            <h4 style=\"margin: 0 0 12px; font-family: 'Montserrat', sans-serif; font-size: 17px; font-weight: 700; color: #0D1117; line-height: 1.45;\">Toplumsal Dayanışma Ruhu ve Sivil Toplum Bilinci</h4>\n            <p style=\"margin: 0 0 20px; font-size: 14px; color: #64748B; line-height: 1.6; text-align: justify;\">Tarihin bizlere yüklediği misyonla, yardımlaşma ve vefa duygularının kurumsallaşması ve derneğimiz bünyesinde gerçekleştireceğimiz geniş çaplı projelerimiz...</p>\n          </div>\n          <div style=\"display: flex; justify-content: space-between; align-items: center; font-size: 12px; color: #94A3B8; border-top: 1px solid #F1F5F9; padding-top: 15px;\">\n            <span><i class=\"fa fa-calendar-days\" style=\"margin-right: 5px;\"></i> Kurumsal Mesaj</span>\n            <a href=\"https://yekpare.net/tr/vkd/kategori/dernegimiz?siteId=7\" style=\"color: #C9A84C; font-weight: 700; text-decoration: none;\">Devamını Oku <i class=\"fa fa-chevron-right\" style=\"font-size: 10px; margin-left: 2px;\"></i></a>\n          </div>\n        </div>\n      </div>\n\n    </div>\n\n    <section style=\"background: linear-gradient(135deg, #8C1A2E, #6E1222); color: #fff; padding: 50px 30px; text-align: center; border-radius: 20px; box-sizing: border-box; box-shadow: 0 10px 20px rgba(140, 26, 46, 0.1);\">\n      <h3 style=\"font-family: 'Montserrat', sans-serif; font-size: 24px; margin-top: 0; margin-bottom: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.5px;\">Kurumsal İş Birliği ve İletişim</h3>\n      <p style=\"max-width: 700px; margin: 0 auto 25px; font-size: 15px; opacity: 0.85; font-weight: 300; line-height: 1.6;\">Resmi heyet görüşmeleri, kurumsal ziyaretler ve dernek ortak çalışma talepleriniz için başkanlık ofisi ile doğrudan irtibata geçebilirsiniz.</p>\n      \n      <div style=\"display: flex; justify-content: center; gap: 15px; flex-wrap: wrap;\">\n        <a href=\"https://yekpare.net/tr/vkd/iletisim\" style=\"background: #C9A84C; color: #0D1117; padding: 12px 35px; border-radius: 8px; font-weight: 700; text-decoration: none; font-size: 14px; text-transform: uppercase; letter-spacing: 0.5px; box-shadow: 0 4px 10px rgba(201, 168, 76, 0.2);\">📬 Başkanlık Ofisine Yazın</a>\n        <a href=\"https://yekpare.net/tr/vkd/kategori/dernegimiz?siteId=7\" style=\"background: rgba(255, 255, 255, 0.1); color: #fff; padding: 12px 35px; border-radius: 8px; font-weight: 600; text-decoration: none; font-size: 14px; border: 1px solid rgba(255, 255, 255, 0.2);\">Dernek Yapısı</a>\n      </div>\n    </section>\n\n  </div>\n</div>","enabled":true,"fullWidth":true},{"id":"b4dca863-f746-435c-a22b-ba77faf57ff5","title":"Faaliyetler","slug":"faaliyetler","bodyHtml":"<div style=\"font-family:'Open Sans',system-ui,sans-serif;color:#1e293b\">\r\n<div class=\"tp-hero\">\r\n  <div class=\"tp-hero-w\">\r\n    <div>\r\n      <div class=\"tp-eyebrow\"><i class=\"fa fa-medal\" style=\"color:#e11d48\"></i> VATAN KAHRAMANLARI DERNEĞİ</div>\r\n      <h1 class=\"tp-h1\">Faaliyetlerimiz <em>Vefa ve Destek Projeleri</em></h1>\r\n      <p class=\"tp-hdesc\">Aziz şehitlerimizin emanetlerine sahip çıkmak, gazilerimize destek olmak ve vatan sevgisini gelecek nesillere aktarmak için yürüttüğümüz çalışmalar.</p>\r\n    </div>\r\n    <div class=\"tp-hero-stats\">\r\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">Şehit</div><div class=\"tp-stat-l\">Emanetleri</div></div>\r\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">Gazi</div><div class=\"tp-stat-l\">Dayanışması</div></div>\r\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">Milli</div><div class=\"tp-stat-l\">Bilinç</div></div>\r\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">2026</div><div class=\"tp-stat-l\">Aktif</div></div>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"tp-bc\">\r\n    <div class=\"tp-bc-w\">\r\n        <a href=\"/\">Ana Sayfa</a>\r\n        <span class=\"sep\">›</span>\r\n        <span>Faaliyetlerimiz</span>\r\n    </div>\r\n</div>\r\n\r\n<div class=\"tp-sec\">\r\n  <div class=\"tp-sec-w\">\r\n    <div class=\"tp-sec-hd\">\r\n        <div class=\"tp-badge tq\" style=\"background-color:#e11d48; color:#fff\">🇹🇷 Faaliyetlerimiz</div>\r\n        <h2 class=\"tp-sec-title\">Neler Yapıyoruz?</h2>\r\n        <p class=\"tp-sec-sub\">Derneğimiz, kahramanlarımızın hatırasını yaşatmak ve ailelerinin yanında olmak için durmaksızın çalışmaktadır.</p>\r\n    </div>\r\n    <div class=\"tp-grid tp-g4\">\r\n      <a href=\"/sosyal-destek\" class=\"tp-card\">\r\n        <div class=\"tp-card-top tq\" style=\"background-color:#e11d48\"></div>\r\n        <div class=\"tp-card-body\">\r\n            <div class=\"tp-card-icon tq\" style=\"color:#e11d48\"><i class=\"fa fa-hand-holding-heart\"></i></div>\r\n            <div class=\"tp-card-title\">Sosyal Yardımlaşma</div>\r\n            <div class=\"tp-card-desc\">Şehit yakınlarımıza ve gazilerimize yönelik maddi ve manevi destek programları.</div>\r\n        </div>\r\n        <div class=\"tp-card-foot\"><span class=\"tp-card-lbl\">Vefa</span><span class=\"tp-card-arrow\">→</span></div>\r\n      </a>\r\n\r\n      <a href=\"/egitim-projeleri\" class=\"tp-card\">\r\n        <div class=\"tp-card-top altin\" style=\"background-color:#1e3a8a\"></div>\r\n        <div class=\"tp-card-body\">\r\n            <div class=\"tp-card-icon altin\" style=\"color:#1e3a8a\"><i class=\"fa fa-graduation-cap\"></i></div>\r\n            <div class=\"tp-card-title\">Eğitim ve Burs</div>\r\n            <div class=\"tp-card-desc\">Kahramanlarımızın çocuklarına eğitim hayatları boyunca sağladığımız burs ve kaynaklar.</div>\r\n        </div>\r\n        <div class=\"tp-card-foot\"><span class=\"tp-card-lbl\">Gelecek</span><span class=\"tp-card-arrow\">→</span></div>\r\n      </a>\r\n\r\n      <a href=\"/milli-bilinc\" class=\"tp-card\">\r\n        <div class=\"tp-card-top yesil\" style=\"background-color:#365314\"></div>\r\n        <div class=\"tp-card-body\">\r\n            <div class=\"tp-card-icon yesil\" style=\"color:#365314\"><i class=\"fa fa-flag\"></i></div>\r\n            <div class=\"tp-card-title\">Milli Bilinç Etkinlikleri</div>\r\n            <div class=\"tp-card-desc\">Genç nesillere vatan sevgisini aşılamak amacıyla düzenlenen konferans ve geziler.</div>\r\n        </div>\r\n        <div class=\"tp-card-foot\"><span class=\"tp-card-lbl\">Ecdat İzinde</span><span class=\"tp-card-arrow\">→</span></div>\r\n      </a>\r\n\r\n      <a href=\"/hukuki-danismanlik\" class=\"tp-card\">\r\n        <div class=\"tp-card-top mor\" style=\"background-color:#475569\"></div>\r\n        <div class=\"tp-card-body\">\r\n            <div class=\"tp-card-icon mor\" style=\"color:#475569\"><i class=\"fa fa-gavel\"></i></div>\r\n            <div class=\"tp-card-title\">Hak ve Hukuk</div>\r\n            <div class=\"tp-card-desc\">Şehit ve gazi ailelerimizin haklarını korumak adına verilen ücretsiz hukuki danışmanlık.</div>\r\n        </div>\r\n        <div class=\"tp-card-foot\"><span class=\"tp-card-lbl\">Adalet</span><span class=\"tp-card-arrow\">→</span></div>\r\n      </a>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"tp-quote-band\" style=\"background-color:#e11d48\">\r\n  <div class=\"tp-quote-band-w\">\r\n    <div class=\"tp-q-text\">\"Sahipsiz olan memleketin batması haktır; sen sahip olursan bu vatan batmayacaktır.\"</div>\r\n    <div class=\"tp-q-src\">— Mehmet Akif Ersoy</div>\r\n  </div>\r\n</div>\r\n\r\n\r\n<div class=\"tp-blog-sec\"><div class=\"tp-blog-sec-w\">\r\n  <div class=\"tp-blog-hd\"><div class=\"tp-blog-hd-bar\" style=\"background-color:#e11d48\"></div><h3>Güncel Faaliyet Haberleri</h3></div>\r\n  \r\n</div></div>\r\n\r\n\r\n<div class=\"tp-cta\" style=\"background-color:#0f172a\">\r\n    <div class=\"tp-cta-w\">\r\n      <div class=\"tp-cta-txt\">\r\n          <h3>Kahramanlarımıza Bir Destek De Sizden</h3>\r\n          <p>Derneğimizin gönüllüsü olun veya bağışlarınızla faaliyetlerimize güç verin.</p>\r\n      </div>\r\n      <div class=\"tp-cta-btns\">\r\n          <a href=\"/bagis\" class=\"tp-btn beyaz\" style=\"background-color:#e11d48; border-color:#e11d48; color:#fff\">❤️ Bağış Yap</a>\r\n          <a href=\"/gonullu-ol\" class=\"tp-btn saydam\">Gönüllü Ol</a>\r\n      </div>\r\n    </div>\r\n</div>\r\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page.faaliyetler.php","importedAt":"2026-05-22T16:07:28.392Z"},{"id":"8cf71e44-ba32-4ba7-a5e7-b657ba86a0ad","title":"Bağış","slug":"bagis","bodyHtml":"<style>:root{--tq:var(--cr);--tq2:var(--cr2);--tq3:var(--cr3);--sin2:#fecaca;--bg:#fff8f5}\r\n.bagis-grid{display:grid;grid-template-columns:1fr 340px;gap:32px;max-width:1180px;margin:0 auto;padding:40px 20px}\r\n.bagis-kutu{background:#fff;border:1px solid var(--sin);overflow:hidden}\r\n.bk-head{background:var(--cr2);padding:22px 24px;border-left:4px solid var(--altin)}\r\n.bk-head h3{font-family:var(--fh);font-size:1.1rem;font-weight:700;color:#fff;margin-bottom:4px}\r\n.bk-head p{font-size:12px;color:rgba(255,255,255,.6)}\r\n.bk-body{padding:22px 24px}\r\n.tutar-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:14px}\r\n.tutar-btn{padding:12px 8px;border:1.5px solid var(--sin);background:#fff;font-family:var(--fh);font-size:14px;font-weight:700;color:var(--yz2);cursor:pointer;transition:all .2s;text-align:center}\r\n.tutar-btn:hover,.tutar-btn.aktif{background:var(--cr);border-color:var(--cr);color:#fff}\r\n.tutar-inp{width:100%;border:1.5px solid var(--sin);padding:11px 14px;font-size:14px;outline:none;font-family:var(--fm);margin-bottom:12px;display:block;transition:border-color .2s}\r\n.tutar-inp:focus{border-color:var(--cr)}\r\n.bagis-go{width:100%;background:var(--cr);color:#fff;border:none;padding:14px;font-family:var(--fh);font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:.8px;cursor:pointer;transition:background .2s}\r\n.bagis-go:hover{background:var(--cr2)}\r\n.etki-kart{background:#fff;border:1px solid var(--sin);padding:20px 16px;text-align:center;transition:all .2s}\r\n.etki-kart:hover{border-color:var(--cr);transform:translateY(-2px);box-shadow:0 4px 16px rgba(139,26,26,.1)}\r\n.etki-em{font-size:2rem;margin-bottom:8px}\r\n.etki-n{font-family:var(--fh);font-size:1.3rem;font-weight:700;color:var(--cr);margin-bottom:4px}\r\n.etki-l{font-size:11px;color:var(--yz2);line-height:1.5}\r\n@media(max-width:860px){.bagis-grid{grid-template-columns:1fr}}</style>\r\n\r\n<div class=\"tp-hero\" style=\"background:linear-gradient(135deg,var(--dk) 0%,var(--cr2) 100%)\">\r\n  <div class=\"tp-hero-w\">\r\n    <div>\r\n      <div class=\"tp-eyebrow\"><i class=\"fa fa-shield-halved\" style=\"color:var(--altin2)\"></i> Vatan Kahramanları Vakfı — Destek</div>\r\n      <h1 class=\"tp-h1\">Destek Ol <em>Vatana Katkıda Bulun</em></h1>\r\n      <p class=\"tp-hdesc\">Şehit aileleri ve gazilere yönelik hizmetlerimizi sürdürebilmek için bağışınıza ihtiyacımız var. Her katkı doğrudan faaliyetlerimize aktarılır.</p>\r\n    </div>\r\n    <div class=\"tp-hero-stats\">\r\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">%100</div><div class=\"tp-stat-l\">Şeffaflık</div></div>\r\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">Güvenli</div><div class=\"tp-stat-l\">SSL Korumalı</div></div>\r\n    </div>\r\n  </div>\r\n</div>\r\n<div class=\"tp-bc\"><div class=\"tp-bc-w\"><a href=\"/\">Ana Sayfa</a><span class=\"sep\">›</span><span>Bağış Yapın</span></div></div>\r\n\r\n<div style=\"max-width:1180px;margin:0 auto;padding:32px 20px 0\">\r\n  <div style=\"text-align:center;margin-bottom:20px\">\r\n    <div style=\"font-family:var(--fh);font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:var(--cr);margin-bottom:6px\">❤️ Neden Destek?</div>\r\n    <h2 style=\"font-family:var(--fh);font-size:1.5rem;color:var(--dk);margin-bottom:6px\">Bağışınız Neye Gider?</h2>\r\n    <p style=\"font-size:12.5px;color:var(--yz2);max-width:520px;margin:0 auto\">Her katkı doğrudan şehit aileleri, gaziler ve vatanseverlik faaliyetlerimize aktarılır.</p>\r\n  </div>\r\n  <div style=\"display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:32px\">\r\n    <div class=\"etki-kart\"><div class=\"etki-em\">🎖️</div><div class=\"etki-n\">Şehit Aileler</div><div class=\"etki-l\">Şehit ailelerine maddi ve manevi destek</div></div>\r\n    <div class=\"etki-kart\"><div class=\"etki-em\">🏅</div><div class=\"etki-n\">Gazi Hakları</div><div class=\"etki-l\">Gazilerimizin hak ve haklarının korunması</div></div>\r\n    <div class=\"etki-kart\"><div class=\"etki-em\">🎓</div><div class=\"etki-n\">Burs Programı</div><div class=\"etki-l\">Şehit çocuklarına eğitim bursu</div></div>\r\n    <div class=\"etki-kart\"><div class=\"etki-em\">📜</div><div class=\"etki-n\">Kahraman Tarihi</div><div class=\"etki-l\">Kahramanların hikâyelerini yaşatma</div></div>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"bagis-grid\">\r\n  <div>\r\n    <div class=\"bagis-kutu\" style=\"margin-bottom:24px\">\r\n      <div class=\"bk-head\"><h3>💳 Online Bağış (Stripe)</h3><p>Güvenli ödeme altyapısı ile kredi/banka kartı ile bağış yapın.</p></div>\r\n      <div class=\"bk-body\">\r\n        <p style=\"font-size:13px;color:var(--yz2);margin-bottom:16px;line-height:1.7\">Bağış miktarınızı seçin veya kendiniz yazın. Stripe güvenli ödeme sayfasına yönlendirileceksiniz.</p>\r\n        <div class=\"tutar-grid\">\r\n          <button class=\"tutar-btn aktif\" type=\"button\">₺100</button>\r\n          <button class=\"tutar-btn\" type=\"button\">₺250</button>\r\n          <button class=\"tutar-btn\" type=\"button\">₺500</button>\r\n          <button class=\"tutar-btn\" type=\"button\">₺1.000</button>\r\n          <button class=\"tutar-btn\" type=\"button\">₺2.500</button>\r\n          <button class=\"tutar-btn\" type=\"button\">Diğer</button>\r\n        </div>\r\n        <input type=\"text\" id=\"bagisKendi\" class=\"tutar-inp\" placeholder=\"Özel miktar girin…\" style=\"display:none\">\r\n        <a target=\"_blank\" rel=\"noopener\" class=\"bagis-go\" style=\"display:block;text-align:center;text-decoration:none\">🛡️ Güvenli Bağış Yap</a>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <div>\r\n    <div class=\"bagis-kutu\">\r\n      <div class=\"bk-head\"><h3>🛡️ Neden Destek Olmalısınız?</h3><p>Kahramanlarınızın yanında olun.</p></div>\r\n      <div class=\"bk-body\">\r\n        <ul style=\"padding-left:0;list-style:none;margin:0;display:flex;flex-direction:column;gap:14px\">\r\n          \r\n          <li style=\"display:flex;align-items:flex-start;gap:12px\">\r\n            \r\n            \r\n          </li>\r\n          \r\n        </ul>\r\n        <div style=\"margin-top:20px;padding-top:16px;border-top:1px solid var(--sin);font-size:11px;color:var(--yz3);text-align:center;line-height:1.7\">\r\n          <i class=\"fa fa-lock\" style=\"color:var(--cr)\"></i> Tüm bağışlar yasal mevzuat kapsamında gerçekleştirilmektedir.<br>\r\n          <i class=\"fa fa-file-alt\" style=\"color:var(--cr)\"></i> Vergi avantajı için makbuz talep edebilirsiniz.\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-bagis.php","importedAt":"2026-05-22T16:07:28.367Z"},{"id":"90af75d4-d821-4123-a046-3d40e25c2868","title":"Şehit Gazi","slug":"sehit-gazi","bodyHtml":"<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n\n<div style=\"font-family:'Open Sans', system-ui, sans-serif; color:#1e293b; background-color:#fff8f5; padding: 0; margin: 0; box-sizing: border-box;\">\n  \n  <div style=\"background: linear-gradient(135deg, #8C1A2E 0%, #450a0a 100%); color: #ffffff; padding: 60px 20px; text-align: center;\">\n    <div style=\"max-width: 1200px; margin: 0 auto;\">\n      <div style=\"display: inline-flex; align-items: center; gap: 6px; background-color: rgba(201, 168, 76, 0.2); color: #C9A84C; padding: 6px 16px; border-radius: 50px; font-size: 13px; font-weight: 600; text-transform: uppercase; margin-bottom: 20px;\">\n        <i class=\"fa-solid fa-shield-halved\"></i> Vatanın Kahramanları\n      </div>\n      <h1 style=\"font-size: 2.5rem; font-weight: 800; margin: 0 0 16px 0; color: #ffffff;\">Şehit & Gazi</h1>\n      <p style=\"max-width: 700px; margin: 0 auto; font-size: 16px; color: #fecaca; line-height: 1.6;\">Türk milletinin bağımsızlığı ve kutsal vatan toprakları için canını feda eden aziz şehitlerimizi ve kahraman gazilerimizi saygı ve ebedi minnetle anıyoruz.</p>\n    </div>\n  </div>\n\n  <div style=\"max-width: 1200px; margin: -30px auto 40px auto; padding: 0 20px; display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 16px;\">\n    <div style=\"background: #ffffff; border: 1px solid #fecaca; border-radius: 12px; padding: 20px; text-align: center; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05);\">\n      <div style=\"font-size: 24px; font-weight: 800; color: #8C1A2E;\">Şehitlerimiz</div>\n      <div style=\"font-size: 13px; color: #64748b; margin-top: 4px;\">Aziz Ruhlar</div>\n    </div>\n    <div style=\"background: #ffffff; border: 1px solid #fecaca; border-radius: 12px; padding: 20px; text-align: center; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05);\">\n      <div style=\"font-size: 24px; font-weight: 800; color: #8C1A2E;\">Gazilerimiz</div>\n      <div style=\"font-size: 13px; color: #64748b; margin-top: 4px;\">Yaşayan Kahramanlar</div>\n    </div>\n    <div style=\"background: #ffffff; border: 1px solid #fecaca; border-radius: 12px; padding: 20px; text-align: center; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05);\">\n      <div style=\"font-size: 24px; font-weight: 800; color: #8C1A2E;\">Milli Anıtlar</div>\n      <div style=\"font-size: 13px; color: #64748b; margin-top: 4px;\">Türkiye ve Dünya Geneli</div>\n    </div>\n  </div>\n\n  <div style=\"max-width: 1200px; margin: 40px auto; padding: 0 20px; display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 24px;\">\n    \n    <a href=\"/turksehitlik\" style=\"background: #ffffff; border: 1px solid #fecaca; border-radius: 12px; padding: 24px; text-decoration: none; color: inherit; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05); transition: transform 0.2s;\">\n      <div style=\"width: 44px; height: 44px; background-color: #fff8f5; color: #8C1A2E; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 20px; margin-bottom: 16px;\"><i class=\"fa-solid fa-monument\"></i></div>\n      <h3 style=\"font-size: 18px; font-weight: 700; color: #6E1222; margin: 0 0 8px 0;\">Türk Şehitlikleri</h3>\n      <p style=\"font-size: 14px; color: #64748b; line-height: 1.5; margin: 0;\">Yurt içi ve yurt dışındaki tarihi şehitliklerimizin coğrafi arşiv bilgileri.</p>\n    </a>\n\n    <a href=\"/kahramanlar\" style=\"background: #ffffff; border: 1px solid #fecaca; border-radius: 12px; padding: 24px; text-decoration: none; color: inherit; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05); transition: transform 0.2s;\">\n      <div style=\"width: 44px; height: 44px; background-color: #fff8f5; color: #8C1A2E; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 20px; margin-bottom: 16px;\"><i class=\"fa-solid fa-feather-alt\"></i></div>\n      <h3 style=\"font-size: 18px; font-weight: 700; color: #6E1222; margin: 0 0 8px 0;\">Destanlar ve Edebiyat</h3>\n      <p style=\"font-size: 14px; color: #64748b; line-height: 1.5; margin: 0;\">Şehit ve gazilerimiz için kaleme alınmış milli marşlar, şiirler ve tarihi hatıralar.</p>\n    </a>\n\n  </div>\n\n  <div style=\"background-color: #ffffff; border-top: 1px solid #fecaca; padding: 30px 20px; text-align: center;\">\n    <div style=\"font-size: 16px; font-weight: 700; color: #8C1A2E; font-style: italic;\">\"Şehit kanıyla yazılan satırlar hiçbir zaman silinmez.\" — Vatan Kahramanları Derneği</div>\n  </div>\n\n</div>","enabled":true,"fullWidth":true},{"id":"234a6833-e366-45c9-876e-091f847a9bfb","title":"Burs Programı","slug":"burs","bodyHtml":"<div style=\"max-width:100%;width:100%;padding:0;margin:0\">\r\n    <div class=\"wp-content-placeholder\">WordPress içerik alanı</div>\r\n    </div>\r\n    \r\n<style>:root{--r:#8C1A2E;--rd:#6E1222;--rl:rgba(140,26,46,.09);--g:#C9A84C;--gl:rgba(201,168,76,.1);--dk:#0D1117;--dk2:#1C2330;--wh:#FAFAF8;--gr:#F5F2ED;--bd:#E4E0D8;--t1:#1A1F28;--t2:#4A5568;--t3:#718096;--fn:'Nunito Sans',sans-serif;--fs:'Merriweather',serif;--w:1440px}\r\n*,*::before,*::after{box-sizing:border-box}\r\n\r\n\r\n.ph{width:100%;background:linear-gradient(150deg,var(--dk) 0%,var(--dk2) 55%,#18060a 100%);padding:72px 40px;position:relative;overflow:hidden;color:#fff}\r\n.ph-w{max-width:var(--w);margin:0 auto;display:grid;grid-template-columns:1.3fr 1fr;gap:60px;align-items:center;position:relative;z-index:1}\r\n.ph-ew{display:inline-flex;align-items:center;gap:7px;background:var(--gl);border:1px solid rgba(201,168,76,.3);color:var(--g);font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;padding:6px 14px;border-radius:20px;margin-bottom:18px}\r\n.ph-h1{font-family:var(--fs);font-size:clamp(1.8rem,3vw,2.8rem);font-weight:700;line-height:1.2;margin-bottom:14px}\r\n.ph-h1 em{color:var(--g);font-style:italic;display:block}\r\n.ph-desc{font-size:14px;color:rgba(255,255,255,.6);line-height:1.8;max-width:500px}\r\n\r\n\r\n.ph-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:rgba(255,255,255,.1);border-radius:12px;overflow:hidden;border:1px solid rgba(255,255,255,.1)}\r\n.ph-si{background:rgba(255,255,255,.04);padding:20px;text-align:center}\r\n.ph-sn{font-size:1.8rem;font-weight:800;color:var(--g);display:block}\r\n.ph-sl{font-size:9px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:rgba(255,255,255,.4)}\r\n\r\n\r\n.sec{width:100%;padding:60px 40px}\r\n.sec:nth-child(even){background:var(--gr)}\r\n.sec-w{max-width:var(--w);margin:0 auto}\r\n.sec-hd{margin-bottom:40px;border-bottom:2px solid var(--bd);padding-bottom:20px}\r\n.sec-title{font-family:var(--fs);font-size:1.6rem;font-weight:700;color:var(--t1)}\r\n.sec-sub{font-size:13px;color:var(--t3);margin-top:5px}\r\n\r\n\r\n.grid{display:grid;gap:20px}.g3{grid-template-columns:repeat(3,1fr)}.g4{grid-template-columns:repeat(4,1fr)}\r\n.card{background:#fff;border:1px solid var(--bd);border-radius:8px;padding:25px;transition:0.25s;display:flex;flex-direction:column}\r\n.card:hover{box-shadow:0 10px 25px rgba(0,0,0,0.08);transform:translateY(-3px)}\r\n.card-icon{font-size:2rem;margin-bottom:15px;color:var(--r)}\r\n.card-title{font-family:var(--fs);font-size:1.1rem;font-weight:700;color:var(--t1);margin-bottom:10px}\r\n.card-desc{font-size:12px;color:var(--t2);line-height:1.7;margin-bottom:15px;flex:1}\r\n.card-list{list-style:none;padding:0;margin:0 0 15px}\r\n.card-list li{font-size:11px;color:var(--t2);display:flex;gap:8px;margin-bottom:5px}\r\n.card-list li::before{content:\"✓\";color:var(--r);font-weight:700}\r\n.card-foot{padding-top:15px;border-top:1px solid var(--bd);display:flex;justify-content:space-between;align-items:center}\r\n.card-lnk{font-size:11px;font-weight:700;color:var(--r);text-decoration:none}\r\n\r\n\r\n.basvuru-box{background:#fff;border:1px solid var(--bd);border-radius:12px;overflow:hidden;max-width:850px;margin:0 auto;box-shadow:0 15px 45px rgba(0,0,0,0.05)}\r\n.basvuru-head{background:linear-gradient(135deg,var(--rd),var(--r));padding:30px;color:#fff}\r\n.basvuru-head h3{font-family:var(--fs);font-size:1.3rem;margin-bottom:5px}\r\n.basvuru-body{padding:40px}\r\n.fg-row{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:20px}\r\n.fg{display:flex;flex-direction:column;gap:8px}\r\n.fg label{font-size:11px;font-weight:700;color:var(--t2);text-transform:uppercase}\r\n.fg input, .fg select, .fg textarea{padding:12px;border:1px solid var(--bd);border-radius:6px;font-family:var(--fn);font-size:13px}\r\n.fg-submit{background:var(--r);color:#fff;border:none;padding:15px;border-radius:6px;font-weight:700;cursor:pointer;transition:0.2s}\r\n.fg-submit:hover{background:var(--rd)}\r\n\r\n@media(max-width:860px){.ph-w,.g3,.g4,.fg-row{grid-template-columns:1fr}.sec,.ph{padding:40px 20px}}</style>\r\n\r\n<div class=\"pw\">\r\n    <div class=\"ph\">\r\n        <div class=\"ph-w\">\r\n            <div>\r\n                <div class=\"ph-ew\">🇹🇷 Vatan Kahramanları Derneği</div>\r\n                <h1 class=\"ph-h1\">Kahramanlarımızın Çocuklarına<em>Milli Vefa Bursu</em></h1>\r\n                <p class=\"ph-desc\">\r\n                    Türkiye'nin 81 ilinde, vatan uğruna canını feda eden kahramanlarımızın emanetlerini geleceğe hazırlıyoruz. \r\n                    <strong>Vatan Kahramanları Vakfı</strong> iş birliğiyle, evlatlarımıza sadece maddi burs değil, uluslararası vizyon sağlıyoruz.\r\n                </p>\r\n            </div>\r\n            <div class=\"ph-stats\">\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">81</span><span class=\"ph-sl\">İl Kapsamı</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">5</span><span class=\"ph-sl\">Türk Devleti</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">14</span><span class=\"ph-sl\">Ülke Ağı</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">🎓</span><span class=\"ph-sl\">Akademik Destek</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">🌍</span><span class=\"ph-sl\">Değişim Prog.</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">100%</span><span class=\"ph-sl\">Vefa Borcu</span></div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"sec\">\r\n        <div class=\"sec-w\">\r\n            <div class=\"sec-hd\">\r\n                <h2 class=\"sec-title\">Eğitim Destek Modellerimiz</h2>\r\n                <p class=\"sec-sub\">Derneğimizin saha gücü ve vakfımızın uluslararası akreditasyonu ile sunulan programlar.</p>\r\n            </div>\r\n            <div class=\"grid g3\">\r\n                <div class=\"card\">\r\n                    <div class=\"card-icon\">🏛️</div>\r\n                    <div class=\"card-title\">Yurt İçi Lisans Bursu</div>\r\n                    <p class=\"card-desc\">Türkiye genelindeki tüm üniversitelerde eğitim gören şehit ve gazi çocuklarına yönelik nakdi burs desteği.</p>\r\n                    <ul class=\"card-list\">\r\n                        <li>Aylık düzenli ödeme planı</li>\r\n                        <li>Kitap ve eğitim materyali desteği</li>\r\n                        <li>Ankara/İstanbul konaklama rehberliği</li>\r\n                    </ul>\r\n                    <div class=\"card-foot\"><a href=\"#basvuru\" class=\"card-lnk\">Hemen Başvur →</a></div>\r\n                </div>\r\n\r\n                <div class=\"card\">\r\n                    <div class=\"card-icon\">🌏</div>\r\n                    <div class=\"card-title\">Türk Dünyası Değişim Programı</div>\r\n                    <p class=\"card-desc\">Vatan Kahramanları Vakfı aracılığıyla Azerbaycan, Kazakistan ve Özbekistan'da eğitim fırsatları.</p>\r\n                    <ul class=\"card-list\">\r\n                        <li>TDT Orhun süreci entegrasyonu</li>\r\n                        <li>Kardeş devletlerde ücretsiz yurt imkânı</li>\r\n                        <li>Kültürel oryantasyon programları</li>\r\n                    </ul>\r\n                    <div class=\"card-foot\"><a href=\"#basvuru\" class=\"card-lnk\">Bilgi Al →</a></div>\r\n                </div>\r\n\r\n                <div class=\"card\">\r\n                    <div class=\"card-icon\">🛡️</div>\r\n                    <div class=\"card-title\">Akademik Mentorluk</div>\r\n                    <p class=\"card-desc\">Evlatlarımızın kariyer yolculuğunda uzman mentorlarımız ile profesyonel rehberlik hizmeti.</p>\r\n                    <ul class=\"card-list\">\r\n                        <li>Kariyer planlama seansları</li>\r\n                        <li>Staj ve işe yerleştirme önceliği</li>\r\n                        <li>Liderlik ve kişisel gelişim eğitimi</li>\r\n                    </ul>\r\n                    <div class=\"card-foot\"><a href=\"#basvuru\" class=\"card-lnk\">Mentor Ol/Başvur →</a></div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"sec\" id=\"basvuru\" style=\"background:var(--wh)\">\r\n        <div class=\"sec-w\">\r\n            <div class=\"basvuru-box\">\r\n                <div class=\"basvuru-head\">\r\n                    <h3>🎓 Burs & Eğitim Başvuru Formu</h3>\r\n                    <p>Vatan kahramanlarımızın emanetleri için öncelikli değerlendirme süreci.</p>\r\n                </div>\r\n                <div class=\"basvuru-body\">\r\n                    <div class=\"fg-row\">\r\n                        <div class=\"fg\"><label>Ad Soyad</label><input type=\"text\" placeholder=\"Örn: Ahmet Yılmaz\"></div>\r\n                        <div class=\"fg\"><label>T.C. Kimlik No</label><input type=\"text\" placeholder=\"11 Haneli TC No\"></div>\r\n                    </div>\r\n                    <div class=\"fg-row\">\r\n                        <div class=\"fg\"><label>E-Posta Adresi</label><input type=\"email\" placeholder=\"ornek@mail.com\"></div>\r\n                        <div class=\"fg\"><label>Telefon (GSM)</label><input type=\"tel\" placeholder=\"05xx xxx xx xx\"></div>\r\n                    </div>\r\n                    <div class=\"fg-row\">\r\n                        <div class=\"fg\"><label>Başvuru Tercihi</label>\r\n                            <select>\r\n                                <option>Yurt İçi Lisans Bursu</option>\r\n                                <option>Türk Dünyası Değişim Programı</option>\r\n                                <option>Lisansüstü Araştırma Desteği</option>\r\n                                <option>Akademik Mentorluk</option>\r\n                            </select>\r\n                        </div>\r\n                        <div class=\"fg\"><label>Yakınlık Derecesi</label>\r\n                            <select>\r\n                                <option>Şehit Yakını (Çocuk/Eş)</option>\r\n                                <option>Gazi Yakını (Çocuk/Eş)</option>\r\n                                <option>Gazinin Kendisi</option>\r\n                            </select>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"fg\" style=\"margin-bottom:20px\"><label>Eğitim Bilgileri ve Notunuz</label><textarea rows=\"4\" placeholder=\"Okuduğunuz okul, bölüm ve varsa özel durumunuzu belirtiniz...\"></textarea></div>\r\n                    <button class=\"fg-submit\" type=\"button\">Vefa Programına Başvuruyu Tamamla</button>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div style=\"background:var(--r); padding:50px 20px; text-align:center; color:#fff\">\r\n        <h3 style=\"font-family:var(--fs); font-size:1.5rem; margin-bottom:15px\">Geleceğe Bir Tuğla Da Siz Koyun</h3>\r\n        <p style=\"margin-bottom:25px; opacity:0.8\">Her bağış, bir kahraman çocuğunun hayallerine açılan kapıdır.</p>\r\n        <div style=\"display:flex; justify-content:center; gap:15px; flex-wrap:wrap\">\r\n            <a href=\"/bagis\" style=\"background:var(--g); color:var(--dk); padding:12px 30px; border-radius:5px; font-weight:700; text-decoration:none\">💝 Bağış Yap</a>\r\n            <a href=\"/iletisim\" style=\"background:transparent; color:#fff; border:1px solid #fff; padding:12px 30px; border-radius:5px; font-weight:700; text-decoration:none\">📩 Kurumsal İletişim</a>\r\n        </div>\r\n    </div>\r\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-burs.php","importedAt":"2026-05-22T16:07:28.370Z"},{"id":"87896b4b-e147-425a-a356-620594fe8ea1","title":"Yeni sayfa","slug":"sayfa-7","bodyHtml":"<p>İçerik</p>","enabled":true,"fullWidth":true},{"id":"wp-template-dunya-sehit-gazi-kuruluslari","title":"Dünya Şehit Gazi Kuruluşları","slug":"dunya-sehit-gazi-kuruluslari","bodyHtml":"<div style=\"max-width:100%;width:100%;padding:0;margin:0\">\n    <div class=\"wp-content-placeholder\">WordPress içerik alanı</div>\n    </div>\n    \n<style>:root {\n  --r:#8C1A2E;--rd:#6E1222;--rl:rgba(140,26,46,.09);\n  --g:#C9A84C;--gl:rgba(201,168,76,.1);\n  --dk:#0D1117;--dk2:#1C2330;--wh:#FAFAF8;\n  --gr:#F5F2ED;--bd:#E4E0D8;\n  --t1:#1A1F28;--t2:#4A5568;--t3:#718096;\n  --fn:'Nunito Sans',system-ui,sans-serif;\n  --fs:'Merriweather',Georgia,serif;\n  --w:1440px;\n}</style>\n\n\n<style>#content,#MainContent,main#content{max-width:100%!important;padding:0!important;width:100%!important;margin:0!important}\n.page-hero,.page-content,.page__heading,.page__header,.page-header,.page-title{display:none!important}</style>\n<style>400;600;700;800&family=Merriweather:ital,wght@0,400;0,700;1,400&display=swap');\n*{box-sizing:border-box}\n.dsg{font-family:'Nunito Sans',system-ui,sans-serif;color:#1A1F28;max-width:1200px;margin:0 auto;padding:0 24px 60px}\n.dsg-hero{background:linear-gradient(135deg,#0D1117,#1C2330);border-radius:4px;padding:28px 36px;margin-bottom:20px}\n.dsg-hero h1{font-family:'Merriweather',Georgia,serif;font-size:1.8rem;font-weight:700;color:#fff;margin-bottom:6px}\n.dsg-hero p{font-size:12.5px;color:rgba(255,255,255,.45)}\n.dsg-stat-row{display:flex;gap:12px;margin-bottom:20px;flex-wrap:wrap}\n.dsg-stat{background:#fff;border:1px solid #EAE6DE;border-radius:4px;padding:10px 16px;text-align:center}\n.dsg-stat strong{display:block;font-size:1.3rem;font-weight:800;color:#8C1A2E}\n.dsg-stat span{font-size:10px;color:#718096}\n.dsg-search{display:flex;border:1px solid #EAE6DE;border-radius:4px;overflow:hidden;background:#fff;margin-bottom:14px}\n.dsg-search input{flex:1;border:none;padding:11px 16px;font-size:13px;font-family:inherit;outline:none}\n.dsg-search button{background:#8C1A2E;border:none;color:#fff;padding:0 20px;cursor:pointer;font-weight:700;font-size:13px;font-family:inherit}\n.dsg-fb-wrap{display:flex;flex-wrap:wrap;gap:6px;margin-bottom:18px}\n.dsg-fb{padding:6px 13px;border:1.5px solid #EAE6DE;border-radius:20px;font-size:11px;font-weight:700;color:#4A5568;background:#fff;cursor:pointer;font-family:inherit;transition:all .2s}\n.dsg-fb:hover,.dsg-fb.on{background:#8C1A2E;border-color:#8C1A2E;color:#fff}\n.dsg-sec-title{font-size:10px;font-weight:800;letter-spacing:3px;text-transform:uppercase;color:#8C1A2E;margin:20px 0 12px;padding-bottom:8px;border-bottom:2px solid #EAE6DE;display:flex;align-items:center;gap:8px}\n.dsg-sec-title::before{content:'';width:16px;height:2px;background:#8C1A2E;display:block}\n.dsg-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}\n.dsg-card{background:#fff;border:1px solid #EAE6DE;border-radius:4px;overflow:hidden;transition:all .2s;display:flex;flex-direction:column}\n.dsg-card:hover{border-color:#8C1A2E;box-shadow:0 3px 12px rgba(0,0,0,.07)}\n.dsg-card-hd{background:linear-gradient(135deg,#1C2330,#2C3547);padding:11px 13px}\n.dsg-flag{font-size:1.3rem;margin-bottom:4px}\n.dsg-card-name{font-size:11.5px;font-weight:700;color:#fff;line-height:1.35;margin-bottom:2px}\n.dsg-card-country{font-size:9px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;color:#C9A84C}\n.dsg-card-body{padding:11px 13px;flex:1;display:flex;flex-direction:column;gap:3px}\n.dsg-row{display:flex;gap:6px;font-size:11px;color:#4A5568;align-items:flex-start}\n.dsg-row a{color:#8C1A2E;font-weight:700;text-decoration:none}\n.dsg-empty{text-align:center;padding:40px;color:#718096;font-size:13px;background:#F5F2ED;border-radius:4px}\n.dsg-wvf{background:linear-gradient(135deg,#8C1A2E,#6E1222);border-radius:4px;padding:18px 22px;margin-bottom:20px;display:flex;align-items:center;gap:14px;text-decoration:none;transition:all .2s}\n.dsg-wvf:hover{transform:translateX(3px)}\n@media(max-width:800px){.dsg-grid{grid-template-columns:1fr 1fr}}\n@media(max-width:480px){.dsg-grid{grid-template-columns:1fr}}</style>\n\n<div class=\"dsg\">\n<div class=\"dsg-hero\">\n  <h1>🌍 Dünya Şehit & Gazi Kuruluşları</h1>\n  <p>Kıta ve ülkelere göre dünya genelinde şehit yakınları ve gazi dernekleri, vakıf ve federasyonları</p>\n  <div style=\"margin-top:12px;display:flex;gap:8px;flex-wrap:wrap\">\n    <span style=\"background:rgba(201,168,76,.15);border:1px solid rgba(201,168,76,.3);color:#C9A84C;padding:3px 11px;border-radius:20px;font-size:10px;font-weight:700\">330+ Kuruluş</span>\n    <span style=\"background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.15);color:rgba(255,255,255,.6);padding:3px 11px;border-radius:20px;font-size:10px;font-weight:700\">6 Kıta · 50+ Ülke</span>\n  </div>\n</div>\n\n<a href=\"https://theworldveterans.org\" target=\"_blank\" rel=\"noopener\" class=\"dsg-wvf\">\n  <div style=\"font-size:2rem;flex-shrink:0\">🌐</div>\n  <div><div style=\"font-size:13px;font-weight:800;color:#fff;margin-bottom:3px\">World Veterans Federation (WVF) — Dünya Gaziler Federasyonu</div>\n  <div style=\"font-size:11.5px;color:rgba(255,255,255,.7)\">60+ ülkede temsilciliği olan en büyük uluslararası gazi çatı örgütü</div></div>\n  <div style=\"margin-left:auto;color:rgba(255,255,255,.5);font-size:1.2rem\">→</div>\n</a>\n\n<div class=\"dsg-stat-row\">\n  <div class=\"dsg-stat\"><strong>330+</strong><span>Kuruluş</span></div>\n  <div class=\"dsg-stat\"><strong>50+</strong><span>Ülke</span></div>\n  <div class=\"dsg-stat\"><strong id=\"dsg-count\">330</strong><span>Gösterilen</span></div>\n</div>\n\n<div class=\"dsg-search\">\n  <input type=\"text\" id=\"dsg-inp\" placeholder=\"Kuruluş adı veya ülke ile arayın...\">\n  <button type=\"button\">🔍 Ara</button>\n</div>\n\n<div class=\"dsg-fb-wrap\">\n  <button class=\"dsg-fb on\" type=\"button\">🌐 Tümü</button>\n  <button class=\"dsg-fb\" type=\"button\">🇪🇺 Avrupa</button>\n  <button class=\"dsg-fb\" type=\"button\">🌎 Amerika</button>\n  <button class=\"dsg-fb\" type=\"button\">🌏 Asya</button>\n  <button class=\"dsg-fb\" type=\"button\">🌍 Afrika</button>\n  <button class=\"dsg-fb\" type=\"button\">🦘 Okyanusya</button>\n</div>\n\n<div id=\"dsg-out\"></div>\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-dunya-sehit-gazi-kuruluslari.php","importedAt":"2026-05-22T16:07:28.371Z"},{"id":"wp-template-hakkimizda","title":"Hakkımızda","slug":"hakkimizda","bodyHtml":"<div style=\"font-family:'Open Sans',system-ui,sans-serif;color:#1e293b\">\n\n<div class=\"tp-hero\">\n  <div class=\"tp-hero-w\">\n    <div>\n      <div class=\"tp-eyebrow\">&#128737; Kahramanlık ve Vatanseverliğin Simgesi</div>\n      <h1 class=\"tp-h1\">Hakkımızda <em>Vatan Kahramanları Derneği</em></h1>\n      <p class=\"tp-hdesc\">Türk milletinin kahramanlık kültürünü yaşatmak, Türk askerinin destanlarını geleceğe taşımak ve vatanseverlik ruhunu tüm dünyada temsil etmek amacıyla yola çıktık.</p>\n    </div>\n    <div class=\"tp-hero-stats\">\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">7/24</div><div class=\"tp-stat-l\">Hizmet Kapasitesi</div></div>\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">Profesyonel</div><div class=\"tp-stat-l\">Müdahale Timi</div></div>\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">Milli</div><div class=\"tp-stat-l\">Birlik Ruhu</div></div>\n      <div class=\"tp-stat\"><div class=\"tp-stat-n\">Küresel</div><div class=\"tp-stat-l\">Etki Alanı</div></div>\n    </div>\n  </div>\n</div>\n\n<div class=\"tp-bc\"><div class=\"tp-bc-w\">\n  <a href=\"/\">Ana Sayfa</a><span class=\"sep\">›</span><span>Hakkımızda</span>\n</div></div>\n\n<div class=\"tp-subnav\"><div class=\"tp-subnav-w\">\n  <a href=\"/hakkimizda\" class=\"aktif\">&#8505; Hakkımızda</a>\n  <a href=\"/faaliyetler\">&#128197; Faaliyetler</a>\n  <a href=\"/genel-baskan\">&#129309; Genel Başkan</a>\n  <a href=\"/bagis\">&#10084; Bağış</a>\n  <a href=\"/iletisim\">&#128233; İletişim</a>\n</div></div>\n\n<div class=\"tp-sec\">\n  <div class=\"tp-sec-w\">\n    <div class=\"tp-iki-kolon\" style=\"display:grid;grid-template-columns:1fr 1fr;gap:40px;align-items:start\">\n      <div>\n        <div class=\"tp-badge tq\" style=\"margin-bottom:12px\">&#127482;&#127479; VATAN KAHRAMANLARI</div>\n        <h2 class=\"tp-sec-title\">Vatan Kahramanları Derneği</h2>\n        <div style=\"font-size:14px;color:var(--yz2);line-height:1.9;margin-top:14px\">\n          <p style=\"margin-bottom:14px\">Vatan Kahramanları Derneği, Türk milletinin kahramanlık kültürünü yaşatmak amacıyla kurulan; sadece emekli askerlerin değil, vatanseverlik ruhuna sahip tüm fertlerin bir araya geldiği güçlü bir platformdur.</p>\n          <p style=\"margin-bottom:14px\">Kurucumuz <strong>Mustafa Özdemir</strong> liderliğinde; Özel Kuvvetler Komutanlığı'ndan gelen disiplin ve saha tecrübesiyle, gerek ulusal güvenlik bilincinin artırılması gerekse toplumsal dayanışmanın güçlendirilmesi için çalışıyoruz.</p>\n          <p>Derneğimiz, savaş alanlarından afet bölgelerine kadar her nerede ihtiyaç varsa orada olmayı, Türk askerinin gücünü ve merhametini temsil etmeyi kendine görev edinmiştir.</p>\n        </div>\n        <div style=\"display:flex;gap:10px;margin-top:20px;flex-wrap:wrap\">\n          <a href=\"/faaliyetler\" class=\"tp-btn tq\">&#128737; Faaliyetlerimiz</a>\n          <a href=\"/bagis\" class=\"tp-btn saydam\" style=\"background:var(--cr);color:#fff;border:none\">&#10084; Bize Destek Olun</a>\n        </div>\n      </div>\n      <div>\n        <div style=\"background:linear-gradient(135deg,var(--dk),var(--dk2));padding:28px;border-left:3px solid var(--altin)\">\n          <div style=\"font-family:'Georgia',serif;font-size:1.05rem;font-style:italic;color:#fff;line-height:1.6;margin-bottom:14px\">\"Vatanın kahramanları, milletinin her anında ve her zorlukta yanındadır.\"</div>\n          <div style=\"font-family:var(--fh);font-size:9.5px;letter-spacing:2px;text-transform:uppercase;color:var(--altin2)\">— Mustafa Özdemir (Genel Başkan)</div>\n        </div>\n        <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:2px;margin-top:2px\">\n          <div style=\"background:var(--bg2);border:1px solid var(--sin2);padding:16px;text-align:center\">\n            <div style=\"font-family:var(--fh);font-size:1.5rem;font-weight:700;color:var(--cr);line-height:1\">TSK</div>\n            <div style=\"font-size:9.5px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;color:var(--yz3);margin-top:3px\">Köklü Tecrübe</div>\n          </div>\n          <div style=\"background:var(--bg2);border:1px solid var(--sin2);padding:16px;text-align:center\">\n            <div style=\"font-family:var(--fh);font-size:1.5rem;font-weight:700;color:var(--cr);line-height:1\">ÖKK</div>\n            <div style=\"font-size:9.5px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;color:var(--yz3);margin-top:3px\">Uzman Kadro</div>\n          </div>\n          <div style=\"background:var(--bg2);border:1px solid var(--sin2);padding:16px;text-align:center\">\n            <div style=\"font-family:var(--fh);font-size:1.5rem;font-weight:700;color:var(--cr);line-height:1\">BİRLİK</div>\n            <div style=\"font-size:9.5px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;color:var(--yz3);margin-top:3px\">Güçlü Dayanışma</div>\n          </div>\n          <div style=\"background:var(--bg2);border:1px solid var(--sin2);padding:16px;text-align:center\">\n            <div style=\"font-family:var(--fh);font-size:1.5rem;font-weight:700;color:var(--cr);line-height:1\">VATAN</div>\n            <div style=\"font-size:9.5px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;color:var(--yz3);margin-top:3px\">Öncelikli Değer</div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<div class=\"tp-sec\" style=\"background:var(--bg2)\">\n  <div class=\"tp-sec-w\">\n    <div class=\"tp-sec-hd\"><div class=\"tp-badge altin\">&#11088; Temel İlkelerimiz</div><h2 class=\"tp-sec-title\">Bizi Güçlü Kılan Değerler</h2></div>\n    <div class=\"tp-deger-grid\">\n      <div class=\"tp-deger\"><div class=\"tp-deger-em\">&#127894;</div><div class=\"tp-deger-title\">Kahramanlık</div><div class=\"tp-deger-desc\">Türk milletinin şanlı geçmişini ve destanlarını geleceğe taşıyoruz.</div></div>\n      <div class=\"tp-deger\"><div class=\"tp-deger-em\">&#127758;</div><div class=\"tp-deger-title\">Uluslararası Etki</div><div class=\"tp-deger-desc\">Türk askerinin gücünü ve yardımseverliğini dünya çapında sergiliyoruz.</div></div>\n      <div class=\"tp-deger\"><div class=\"tp-deger-em\">&#128680;</div><div class=\"tp-deger-title\">Afet Müdahale</div><div class=\"tp-deger-desc\">Profesyonel arama-kurtarma timlerimizle afet anında milletimizin yanındayız.</div></div>\n      <div class=\"tp-deger\"><div class=\"tp-deger-em\">&#129309;</div><div class=\"tp-deger-title\">Dayanışma</div><div class=\"tp-deger-desc\">Zor koşullarda omuz omuza vermiş kahramanları tek bir çatı altında buluşturuyoruz.</div></div>\n      <div class=\"tp-deger\"><div class=\"tp-deger-em\">&#128737;</div><div class=\"tp-deger-title\">Güvenlik ve Hizmet</div><div class=\"tp-deger-desc\">Mayın temizleme ve bomba imha gibi kritik alanlarda uzmanlığımızı sunuyoruz.</div></div>\n      <div class=\"tp-deger\"><div class=\"tp-deger-em\">&#127482;&#127479;</div><div class=\"tp-deger-title\">Vatanseverlik</div><div class=\"tp-deger-desc\">Her bir üyemizle vatanımıza olan bağlılığımızı eylemlerimizle gösteriyoruz.</div></div>\n    </div>\n  </div>\n</div>\n\n\n<div class=\"tp-blog-sec\"><div class=\"tp-blog-sec-w\">\n  <div class=\"tp-blog-hd\"><div class=\"tp-blog-hd-bar\"></div><h3>Son Faaliyet ve Operasyonlar</h3></div>\n  \n</div></div>\n\n\n<div class=\"tp-cta\"><div class=\"tp-cta-w\">\n  <div class=\"tp-cta-txt\"><h3>Vatan Hizmetinde Bize Katılın</h3><p>Vatan Kahramanları Derneği'nin insani yardım ve güvenlik çalışmalarına destek olun.</p></div>\n  <div class=\"tp-cta-btns\">\n    <a href=\"/bagis\" class=\"tp-btn beyaz\">&#128157; Bağış Yapın</a>\n    <a href=\"/iletisim\" class=\"tp-btn saydam\">&#128233; Bizimle İletişime Geçin</a>\n  </div>\n</div></div>\n\n<style>@media(max-width:768px){\n  .tp-iki-kolon{grid-template-columns:1fr!important;gap:24px!important}\n}</style>\n\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-hakkimizda.php","importedAt":"2026-05-22T16:07:28.372Z"},{"id":"wp-template-hizmet-bolgesi","title":"Hizmet Bölgeleri","slug":"hizmet-bolgesi","bodyHtml":"<div style=\"max-width:100%;width:100%;padding:0;margin:0\">\r\n    <div class=\"wp-content-placeholder\">WordPress içerik alanı</div>\r\n    </div>\r\n    \r\n<style>:root{--r:#8C1A2E;--rd:#6E1222;--rl:rgba(140,26,46,.09);--g:#C9A84C;--gl:rgba(201,168,76,.1);--dk:#0D1117;--dk2:#1C2330;--wh:#FAFAF8;--gr:#F5F2ED;--bd:#E4E0D8;--t1:#1A1F28;--t2:#4A5568;--t3:#718096;--fn:'Nunito Sans',sans-serif;--fs:'Merriweather',serif;--w:1440px}\r\n*,*::before,*::after{box-sizing:border-box}\r\n\r\n\r\n.hero{width:100%;background:linear-gradient(150deg,var(--dk) 0%,var(--dk2) 55%,#18060a 100%);padding:64px 40px;position:relative;overflow:hidden;color:#fff}\r\n.hero-inner{max-width:var(--w);margin:0 auto;display:grid;grid-template-columns:1.4fr 1fr;gap:60px;align-items:center;position:relative;z-index:1}\r\n.hero-eyebrow{display:inline-flex;align-items:center;gap:7px;background:var(--gl);border:1px solid rgba(201,168,76,.3);color:var(--g);font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;padding:6px 14px;border-radius:20px;margin-bottom:18px}\r\n.hero h1{font-family:var(--fs);font-size:clamp(1.8rem,3vw,2.8rem);font-weight:700;line-height:1.2;margin-bottom:14px}\r\n.hero h1 em{color:var(--g);font-style:italic;display:block}\r\n.hero-desc{font-size:14px;color:rgba(255,255,255,.6);line-height:1.8;max-width:550px}\r\n\r\n\r\n.stat-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:rgba(255,255,255,.1);border-radius:12px;overflow:hidden;border:1px solid rgba(255,255,255,.1)}\r\n.stat-item{background:rgba(255,255,255,.04);padding:20px;text-align:center}\r\n.stat-num{font-size:1.8rem;font-weight:800;color:var(--g);display:block;line-height:1}\r\n.stat-lbl{font-size:9px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:rgba(255,255,255,.4);margin-top:5px}\r\n\r\n\r\n.sec{width:100%;padding:60px 40px}\r\n.sec:nth-child(even){background:var(--gr)}\r\n.sec-w{max-width:var(--w);margin:0 auto}\r\n.sec-head{margin-bottom:40px;border-bottom:2px solid var(--bd);padding-bottom:20px;display:flex;justify-content:space-between;align-items:flex-end}\r\n.sh-title{font-family:var(--fs);font-size:1.6rem;font-weight:700;color:var(--t1)}\r\n.sh-sub{font-size:13px;color:var(--t3);margin-top:5px}\r\n\r\n\r\n.ugrid{display:grid;grid-template-columns:repeat(auto-fill, minmax(240px, 1fr));gap:20px}\r\n.uc{background:#fff;border:1px solid var(--bd);border-radius:8px;padding:20px;transition:0.25s}\r\n.uc:hover{box-shadow:0 10px 25px rgba(0,0,0,0.08);transform:translateY(-3px)}\r\n.uc-head{display:flex;align-items:center;gap:12px;margin-bottom:15px}\r\n.uc-flag{font-size:2rem}\r\n.uc-name{font-family:var(--fs);font-size:1.1rem;font-weight:700;color:var(--t1)}\r\n.uc-tag{display:inline-block;font-size:9px;font-weight:700;padding:3px 8px;border-radius:4px;text-transform:uppercase;letter-spacing:0.5px}\r\n.tag-uye{background:var(--rl);color:var(--r)}\r\n.tag-goz{background:#EFF6FF;color:#1D4ED8}\r\n.tag-dost{background:#F0FDF4;color:#15803D}\r\n.uc-desc{font-size:12px;color:var(--t2);line-height:1.6;margin-top:12px}\r\n\r\n@media(max-width:860px){.hero-inner{grid-template-columns:1fr}.sec,.hero{padding:40px 20px}}</style>\r\n\r\n<div class=\"hero\">\r\n    <div class=\"hero-inner\">\r\n        <div>\r\n            <div class=\"hero-eyebrow\">🇹🇷 MİLLİ VEFA AĞI</div>\r\n            <h1>Vatan Kahramanları Derneği<em>81 İlde, Tek Yürek</em></h1>\r\n            <p class=\"hero-desc\">\r\n                Derneğimiz, Türkiye'nin 81 ilinde ve tüm ilçelerinde; vatan uğruna canını siper etmiş kahramanlarımızın, gazilerimizin ve aziz şehitlerimizin emanetlerinin yanındadır. \r\n                <br><br>\r\n                Saha operasyonlarımızı dernek çatısı altında <strong>vefa</strong> ilkesiyle yürütürken, <strong>Vatan Kahramanları Vakfı</strong> aracılığıyla uluslararası arenada stratejik bir güç merkezi olarak faaliyet gösteriyoruz.\r\n            </p>\r\n        </div>\r\n        <div class=\"stat-grid\">\r\n            <div class=\"stat-item\"><span class=\"stat-num\">81</span><span class=\"stat-lbl\">İl Kapsamı</span></div>\r\n            <div class=\"stat-item\"><span class=\"stat-num\">922</span><span class=\"stat-lbl\">İlçe Ağı</span></div>\r\n            <div class=\"stat-item\"><span class=\"stat-num\">501c3</span><span class=\"stat-lbl\">Uluslararası Statü</span></div>\r\n            <div class=\"stat-item\"><span class=\"stat-num\">14</span><span class=\"stat-lbl\">Ülke Ağı</span></div>\r\n            <div class=\"stat-item\"><span class=\"stat-num\">5</span><span class=\"stat-lbl\">Kıta Faaliyeti</span></div>\r\n            <div class=\"stat-item\"><span class=\"stat-num\">∞</span><span class=\"stat-lbl\">Milli Vefa</span></div>\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<div class=\"sec\">\r\n    <div class=\"sec-w\">\r\n        <div class=\"sec-head\">\r\n            <div>\r\n                <h2 class=\"sh-title\">Vatan Kahramanları Vakfı — Küresel Faaliyet Alanı</h2>\r\n                <p class=\"sh-sub\">Vakfımız, aşağıdaki dost ve kardeş coğrafyalarda insani yardım ve stratejik iş birliği yürütmektedir.</p>\r\n            </div>\r\n        </div>\r\n\r\n        <div class=\"ugrid\">\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇦🇿</span><span class=\"uc-name\">Azerbaycan</span></div>\r\n                <span class=\"uc-tag tag-uye\">TDT Tam Üye</span>\r\n                <p class=\"uc-desc\">\"Tek Millet İki Devlet\" anlayışı ile gazi ve şehit ailelerimize yönelik aktif saha desteği.</p>\r\n            </div>\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇰🇿</span><span class=\"uc-name\">Kazakistan</span></div>\r\n                <span class=\"uc-tag tag-uye\">TDT Tam Üye</span>\r\n                <p class=\"uc-desc\">Orta Asya'nın parlayan yıldızında Türk dünyası bütünleşmesi ve sosyal yardım projeleri.</p>\r\n            </div>\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇰🇬</span><span class=\"uc-name\">Kırgızistan</span></div>\r\n                <span class=\"uc-tag tag-uye\">TDT Tam Üye</span>\r\n                <p class=\"uc-desc\">Ata yurdunda şehit emanetlerine yönelik dayanışma ve eğitim destek ağları.</p>\r\n            </div>\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇺🇿</span><span class=\"uc-name\">Özbekistan</span></div>\r\n                <span class=\"uc-tag tag-uye\">TDT Tam Üye</span>\r\n                <p class=\"uc-desc\">Medeniyetimizin beşiğinde kurumsal temsil ve insani yardım faaliyetleri.</p>\r\n            </div>\r\n\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇨🇾</span><span class=\"uc-name\">K.K.T.C.</span></div>\r\n                <span class=\"uc-tag tag-goz\">TDT Gözlemci</span>\r\n                <p class=\"uc-desc\">Kıbrıs Barış Harekâtı gazilerimiz ve aileleri için kesintisiz vefa hizmetleri.</p>\r\n            </div>\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇹🇲</span><span class=\"uc-name\">Türkmenistan</span></div>\r\n                <span class=\"uc-tag tag-goz\">TDT Gözlemci</span>\r\n                <p class=\"uc-desc\">Türk dünyası enerji ve kültür hattında diplomatik ve sosyal katkı odaklı çalışmalar.</p>\r\n            </div>\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇭🇺</span><span class=\"uc-name\">Macaristan</span></div>\r\n                <span class=\"uc-tag tag-goz\">TDT Gözlemci</span>\r\n                <p class=\"uc-desc\">Avrupa'daki Türk mirasını koruma ve stratejik lobi faaliyetleri.</p>\r\n            </div>\r\n\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇵🇰</span><span class=\"uc-name\">Pakistan</span></div>\r\n                <span class=\"uc-tag tag-dost\">Stratejik Dost</span>\r\n                <p class=\"uc-desc\">En yakın müttefikimiz ile savunma ve sosyal dayanışma projeleri.</p>\r\n            </div>\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇧🇦</span><span class=\"uc-name\">Bosna Hersek</span></div>\r\n                <span class=\"uc-tag tag-dost\">Osmanlı Mirası</span>\r\n                <p class=\"uc-desc\">Balkanlar'daki Osmanlı mirasının korunması ve gazi ailelerine destek faaliyetleri.</p>\r\n            </div>\r\n            <div class=\"uc\">\r\n                <div class=\"uc-head\"><span class=\"uc-flag\">🇽🇰</span><span class=\"uc-name\">Kosova</span></div>\r\n                <span class=\"uc-tag tag-dost\">Osmanlı Mirası</span>\r\n                <p class=\"uc-desc\">Evlad-ı Fatihan diyarı Kosova'da şehit yakınları ve gazilerimize yönelik insani yardım ağı.</p>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-hizmet-bolgesi.php","importedAt":"2026-05-22T16:07:28.373Z"},{"id":"wp-template-hukuk-savunuculuk","title":"Hukuk & Savunuculuk","slug":"hukuk-savunuculuk","bodyHtml":"<div style=\"max-width:100%;width:100%;padding:0;margin:0\">\n    <div class=\"wp-content-placeholder\">WordPress içerik alanı</div>\n    </div>\n    \n\n<style>#content,#MainContent,main#content{max-width:100%!important;padding:0!important;width:100%!important;margin:0!important}\n.page-hero,.page-content,.page__heading,.page__header,.page-header,.page-title{display:none!important}</style>\n<style>:root{--r:#8C1A2E;--rd:#6E1222;--rl:rgba(140,26,46,.09);--g:#C9A84C;--gl:rgba(201,168,76,.1);--dk:#0D1117;--dk2:#1C2330;--wh:#FAFAF8;--gr:#F5F2ED;--bd:#E4E0D8;--t1:#1A1F28;--t2:#4A5568;--t3:#718096;--fn:'Nunito Sans',system-ui,sans-serif;--fs:'Merriweather',Georgia,serif;--w:1440px}\n*,*::before,*::after{box-sizing:border-box}\na{text-decoration:none;color:inherit}img{max-width:100%;display:block}ul{list-style:none;padding:0;margin:0}\n.ph{width:100%;background:linear-gradient(150deg,var(--dk) 0%,var(--dk2) 55%,#18060a 100%);padding:72px 40px 60px;position:relative;overflow:hidden}\n.ph::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse 60% 70% at 80% 50%,rgba(140,26,46,.22) 0%,transparent 65%)}\n.ph-w{max-width:var(--w);margin:0 auto;display:grid;grid-template-columns:1.3fr 1fr;gap:60px;align-items:center;position:relative;z-index:1}\n.ph-ew{display:inline-flex;align-items:center;gap:7px;background:rgba(201,168,76,.12);border:1px solid rgba(201,168,76,.3);color:var(--g);font-size:9.5px;font-weight:700;letter-spacing:2.5px;text-transform:uppercase;padding:6px 14px;border-radius:20px;margin-bottom:18px}\n.ph-h1{font-family:var(--fs);font-size:clamp(1.8rem,3vw,2.8rem);font-weight:700;color:#fff;line-height:1.15;margin-bottom:14px}\n.ph-h1 em{color:var(--g);font-style:italic;display:block}\n.ph-desc{font-size:13.5px;color:rgba(255,255,255,.5);line-height:1.85;max-width:500px}\n.ph-desc strong{color:rgba(255,255,255,.75)}\n.ph-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:rgba(255,255,255,.07);border-radius:8px;overflow:hidden;border:1px solid rgba(255,255,255,.07)}\n.ph-si{background:rgba(255,255,255,.04);padding:20px 22px;transition:background .2s}\n.ph-si:hover{background:rgba(255,255,255,.07)}\n.ph-sn{font-size:2rem;font-weight:800;color:var(--g);line-height:1;margin-bottom:4px}\n.ph-sl{font-size:9px;font-weight:700;letter-spacing:1.8px;text-transform:uppercase;color:rgba(255,255,255,.3)}\n.pnav{background:var(--dk2);width:100%}.pnav-in{max-width:var(--w);margin:0 auto;display:flex;overflow-x:auto;scrollbar-width:none}\n.pnav-in::-webkit-scrollbar{display:none}\n.pnav a{display:flex;align-items:center;gap:7px;padding:13px 20px;font-size:10.5px;font-weight:600;color:rgba(255,255,255,.4);text-decoration:none;border-right:1px solid rgba(255,255,255,.06);transition:all .2s;white-space:nowrap;font-family:var(--fn)}\n.pnav a:hover,.pnav a.on{color:var(--g);background:rgba(201,168,76,.06)}\n.pbc{max-width:var(--w);margin:0 auto;padding:13px 40px;display:flex;align-items:center;gap:6px;font-size:11px;color:var(--t3);border-bottom:1px solid var(--bd)}\n.pbc a{color:var(--r);text-decoration:none;font-weight:600}\n.sec{width:100%;padding:48px 40px}.sec:nth-child(even){background:var(--gr)}\n.sec-w{max-width:var(--w);margin:0 auto}\n.sec-hd{margin-bottom:26px;padding-bottom:16px;border-bottom:2px solid var(--bd)}\n.badge{display:inline-flex;align-items:center;gap:5px;font-size:8.5px;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;padding:3px 9px;border-radius:20px;margin-bottom:9px;border:1px solid}\n.badge.r{background:var(--rl);color:var(--r);border-color:rgba(140,26,46,.2)}.badge.g{background:var(--gl);color:#7a5a00;border-color:rgba(201,168,76,.3)}.badge.b{background:#EFF6FF;color:#1D4ED8;border-color:#BFDBFE}.badge.gr{background:#F0FDF4;color:#15803D;border-color:#BBF7D0}.badge.p{background:#F5F3FF;color:#6D28D9;border-color:#DDD6FE}\n.sec-title{font-family:var(--fs);font-size:1.5rem;font-weight:700;color:var(--t1);margin-bottom:6px}\n.sec-sub{font-size:13px;color:var(--t3);line-height:1.7;max-width:680px}\n.grid{display:grid;gap:14px}.g4{grid-template-columns:repeat(4,1fr)}.g3{grid-template-columns:repeat(3,1fr)}.g2{grid-template-columns:repeat(2,1fr)}\n.card{background:#fff;border:1px solid var(--bd);border-radius:8px;overflow:hidden;display:flex;flex-direction:column;transition:all .22s}\n.card:hover{box-shadow:0 8px 32px rgba(0,0,0,.09);transform:translateY(-2px)}\n.card-st{height:4px}.card-st.r{background:linear-gradient(90deg,var(--r),#c0392b)}.card-st.g{background:linear-gradient(90deg,#15803D,#22c55e)}.card-st.b{background:linear-gradient(90deg,#1D4ED8,#60a5fa)}.card-st.p{background:linear-gradient(90deg,#6D28D9,#8b5cf6)}.card-st.gold{background:linear-gradient(90deg,var(--g),#e0a030)}.card-st.t{background:linear-gradient(90deg,#0a5c6e,#0e9aa0)}.card-st.dk{background:linear-gradient(90deg,#0f2c5c,#1d4ed8)}\n.card-body{padding:22px 22px 16px;flex:1;display:flex;flex-direction:column;gap:10px}\n.card-icon{width:52px;height:52px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:1.4rem;margin-bottom:6px}\n.card-icon.r{background:var(--rl);color:var(--r)}.card-icon.g{background:#F0FDF4;color:#15803D}.card-icon.b{background:#EFF6FF;color:#1D4ED8}.card-icon.p{background:#F5F3FF;color:#6D28D9}.card-icon.gold{background:var(--gl);color:#7a5a00}.card-icon.t{background:#ECFEFF;color:#0a5c6e}.card-icon.dk{background:#EFF6FF;color:#0f2c5c}\n.card-title{font-family:var(--fs);font-size:1rem;font-weight:700;color:var(--t1);line-height:1.3}\n.card-desc{font-size:12px;color:var(--t2);line-height:1.75;flex:1}\n.card-list{list-style:none;padding:0;margin:6px 0 0;display:flex;flex-direction:column;gap:4px}\n.card-list li{font-size:11px;color:var(--t2);display:flex;gap:7px;line-height:1.5}\n.card-list li::before{content:\"✓\";color:var(--r);font-weight:700;flex-shrink:0}\n.card-foot{padding:10px 20px;border-top:1px solid var(--bd);background:var(--gr);display:flex;align-items:center;justify-content:space-between}\n.card-lbl{font-size:9px;font-weight:700;letter-spacing:.5px;text-transform:uppercase;color:var(--t3)}\n.card-lnk{font-size:10.5px;font-weight:700;color:var(--r);text-decoration:none}\n.ctaband{background:var(--r);padding:40px;width:100%}\n.ctaband-w{max-width:var(--w);margin:0 auto;display:flex;align-items:center;justify-content:space-between;gap:32px;flex-wrap:wrap}\n.ctaband-text h3{font-family:var(--fs);font-size:1.3rem;font-weight:700;color:#fff;margin-bottom:6px}\n.ctaband-text p{font-size:13px;color:rgba(255,255,255,.65);line-height:1.6}\n.ctabtns{display:flex;gap:10px;flex-wrap:wrap}\n.pbtn{display:inline-flex;align-items:center;gap:7px;padding:11px 22px;border-radius:4px;font-size:12px;font-weight:700;text-decoration:none;font-family:var(--fn);transition:all .2s}\n.pbtn.wh{background:#fff;color:var(--r)}.pbtn.wh:hover{background:#f5e8e8}\n.pbtn.ol{background:transparent;color:#fff;border:1.5px solid rgba(255,255,255,.45)}.pbtn.ol:hover{background:rgba(255,255,255,.1)}\n.qband{background:linear-gradient(135deg,var(--dk),var(--dk2));border-top:3px solid var(--g);padding:52px 40px;text-align:center;width:100%}\n.qband-w{max-width:var(--w);margin:0 auto}\n.qband-text{font-family:var(--fs);font-size:clamp(1.2rem,2vw,1.8rem);font-style:italic;color:#fff;max-width:760px;margin:0 auto 14px;line-height:1.5}\n.qband-text em{color:var(--g)}\n.qband-src{font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:rgba(255,255,255,.35)}\n@media(max-width:1200px){.g4{grid-template-columns:repeat(2,1fr)}}\n@media(max-width:860px){.g3,.g2{grid-template-columns:repeat(2,1fr)}.ph-w{grid-template-columns:1fr;gap:32px}.sec,.ph,.ctaband,.qband{padding:40px 24px}.pbc{padding:12px 24px}}\n@media(max-width:540px){.g4,.g3,.g2{grid-template-columns:1fr}}\n\n.haklar-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}\n.hak-card{background:#fff;border:1px solid var(--bd);border-radius:8px;padding:20px 16px;text-align:center;text-decoration:none;transition:all .22s;display:flex;flex-direction:column;align-items:center;gap:8px}\n.hak-card:hover{border-color:var(--r);box-shadow:0 4px 18px rgba(0,0,0,.08);transform:translateY(-2px)}\n.hak-icon{width:44px;height:44px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:1.3rem;background:var(--rl);color:var(--r)}\n.hak-title{font-size:11.5px;font-weight:700;color:var(--t1);line-height:1.3}\n.hak-desc{font-size:10.5px;color:var(--t3);line-height:1.4}\n.hak-link{font-size:10px;font-weight:700;color:var(--r)}\n.faq-list{display:flex;flex-direction:column;gap:12px}\n.faq-item{background:#fff;border:1px solid var(--bd);border-radius:8px;overflow:hidden}\n.faq-q{padding:16px 20px;font-size:13px;font-weight:700;color:var(--t1);cursor:pointer;display:flex;align-items:center;justify-content:space-between;gap:16px}\n.faq-q:hover{background:var(--gr)}\n.faq-q::after{content:\"+\";font-size:1.3rem;color:var(--r);flex-shrink:0}\n.faq-a{padding:0 20px 16px;font-size:12.5px;color:var(--t2);line-height:1.8}\n.pw{font-family:var(--fn);background:var(--wh);color:var(--t1)}\n@media(max-width:1100px){.haklar-grid{grid-template-columns:repeat(2,1fr)}}</style>\n\n<div class=\"pw\">\n\n<div class=\"ph\">\n  <div class=\"ph-w\">\n    <div>\n      <div class=\"ph-ew\">⚖️ Hukuk &amp; Savunuculuk</div>\n      <h1 class=\"ph-h1\">Haklarınız İçin<em>Yanınızdayız</em></h1>\n      <p class=\"ph-desc\">Şehit yakınları ve gazilerin ulusal ve uluslararası hukuki haklarının korunması için <strong>aktif savunuculuk faaliyetleri, ücretsiz danışmanlık ve 26 ülke haklar rehberi</strong> sunuyoruz.</p>\n    </div>\n    <div>\n      <div class=\"ph-stats\">\n        <div class=\"ph-si\"><div class=\"ph-sn\">26</div><div class=\"ph-sl\">Ülke Rehberi</div></div>\n        <div class=\"ph-si\"><div class=\"ph-sn\">6</div><div class=\"ph-sl\">Hak Kategorisi</div></div>\n        <div class=\"ph-si\"><div class=\"ph-sn\">7/24</div><div class=\"ph-sl\">Danışma Hattı</div></div>\n        <div class=\"ph-si\"><div class=\"ph-sn\">0312</div><div class=\"ph-sl\">963 07 95</div></div>\n        <div class=\"ph-si\"><div class=\"ph-sn\">Ücretsiz</div><div class=\"ph-sl\">Hukuki Danışmanlık</div></div>\n        <div class=\"ph-si\"><div class=\"ph-sn\">⚖️</div><div class=\"ph-sl\">Hukuki Savunuculuk</div></div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<div class=\"pnav\"><div class=\"pnav-in\">\n  <a href=\"/hukuk-savunuculuk\" class=\"on\">⚖️ Hukuk &amp; Savunuculuk</a>\n  <a href=\"/sehit-gazi-haklari\">📋 Şehit &amp; Gazi Hakları</a>\n  <a href=\"/uluslararasi-sehit-gazi-haklari\">🌍 Uluslararası Haklar</a>\n  <a href=\"/insani-yardim\">🔴 İnsani Yardım</a>\n  <a href=\"/isbirligi\">📋 Tüm Programlar</a>\n  <a href=\"/iletisim\">📞 Danışma</a>\n</div></div>\n<div class=\"pbc\"><a href=\"/\">Ana Sayfa</a> › <a href=\"/isbirligi\">İşbirliği</a> › <span>Hukuk &amp; Savunuculuk</span></div>\n\n\n<div class=\"sec\">\n  <div class=\"sec-w\">\n    <div class=\"sec-hd\">\n      <div class=\"badge p\">⚡ Hızlı Erişim</div>\n      <div class=\"sec-title\">Hak Kategorileri</div>\n      <div class=\"sec-sub\">Şehit ailesi ve gazilere yönelik temel hak alanlarına hızla ulaşın.</div>\n    </div>\n    <div class=\"haklar-grid\">\n      <a href=\"/sehit-gazi-haklari\" class=\"hak-card\"><div class=\"hak-icon\"><i class=\"fa fa-money\"></i></div><div class=\"hak-title\">Maaş &amp; Tazminat</div><div class=\"hak-desc\">Şehit ve gazi maaşları, tazminat hakları</div><div class=\"hak-link\">Detay →</div></a>\n      <a href=\"/sehit-gazi-haklari\" class=\"hak-card\"><div class=\"hak-icon\"><i class=\"fa fa-home\"></i></div><div class=\"hak-title\">Konut Hakları</div><div class=\"hak-desc\">TOKİ ve konut destekleri</div><div class=\"hak-link\">Detay →</div></a>\n      <a href=\"/sehit-gazi-haklari\" class=\"hak-card\"><div class=\"hak-icon\"><i class=\"fa fa-heartbeat\"></i></div><div class=\"hak-title\">Sağlık Hakları</div><div class=\"hak-desc\">SGK ve ücretsiz sağlık hizmetleri</div><div class=\"hak-link\">Detay →</div></a>\n      <a href=\"/sehit-gazi-haklari\" class=\"hak-card\"><div class=\"hak-icon\"><i class=\"fa fa-graduation-cap\"></i></div><div class=\"hak-title\">Eğitim Hakları</div><div class=\"hak-desc\">KYK ve burs öncelikleri</div><div class=\"hak-link\">Detay →</div></a>\n      <a href=\"/uluslararasi-sehit-gazi-haklari\" class=\"hak-card\"><div class=\"hak-icon\"><i class=\"fa fa-globe\"></i></div><div class=\"hak-title\">Uluslararası Haklar</div><div class=\"hak-desc\">26 ülke karşılaştırmalı rehber</div><div class=\"hak-link\">Detay →</div></a>\n      <a href=\"/sosyal-hizmetler\" class=\"hak-card\"><div class=\"hak-icon\"><i class=\"fa fa-hospital-o\"></i></div><div class=\"hak-title\">Sosyal Hizmetler</div><div class=\"hak-desc\">e-Devlet başvuru rehberi</div><div class=\"hak-link\">Detay →</div></a>\n      <a href=\"/turkiye-sehit-gazi-dernekleri\" class=\"hak-card\"><div class=\"hak-icon\"><i class=\"fa fa-map-marker\"></i></div><div class=\"hak-title\">Türkiye Dernekleri</div><div class=\"hak-desc\">401 dernek — il il rehber</div><div class=\"hak-link\">Detay →</div></a>\n      <a href=\"/dunya-sehit-gazi-kuruluslari\" class=\"hak-card\"><div class=\"hak-icon\"><i class=\"fa fa-building-o\"></i></div><div class=\"hak-title\">Dünya Kuruluşları</div><div class=\"hak-desc\">330+ dünya gazi kuruluşu</div><div class=\"hak-link\">Detay →</div></a>\n    </div>\n  </div>\n</div>\n\n\n<div class=\"sec\">\n  <div class=\"sec-w\">\n    <div class=\"sec-hd\">\n      <div class=\"badge p\">⚖️ Savunuculuk Programları</div>\n      <div class=\"sec-title\">Nasıl Savunuculuk Yapıyoruz?</div>\n      <div class=\"sec-sub\">Ulusal ve uluslararası platformlarda şehit ailesi ve gazi haklarının korunması için çok katmanlı savunuculuk.</div>\n    </div>\n    <div class=\"grid g3\">\n      <div class=\"card\"><div class=\"card-st p\"></div><div class=\"card-body\"><div class=\"card-icon p\"><i class=\"fa fa-balance-scale\"></i></div><div class=\"card-title\">Ulusal Hak Danışmanlığı</div><div class=\"card-desc\">Türkiye'deki şehit ailesi ve gazi haklarının eksiksiz kullanılması için ücretsiz danışmanlık. ASHB, SGK ve ilgili bakanlıklarla koordineli süreç takibi.</div><ul class=\"card-list\"><li>Maaş bağlama başvuru rehberliği</li><li>Tazminat hakkı tespit ve takibi</li><li>Konut başvurusu koordinasyonu</li><li>Ücretsiz hukuki danışmanlık</li></ul></div><div class=\"card-foot\"><span class=\"card-lbl\">0312 963 07 95</span><a href=\"/iletisim\" class=\"card-lnk\">Danış →</a></div></div>\n      <div class=\"card\"><div class=\"card-st p\"></div><div class=\"card-body\"><div class=\"card-icon p\"><i class=\"fa fa-flag\"></i></div><div class=\"card-title\">Uluslararası Haklar Rehberi</div><div class=\"card-desc\">26 ülkedeki gazi ve şehit ailesi haklarının karşılaştırmalı belgesi. En iyi uygulamaların Türk dünyasına aktarılması için savunuculuk.</div><ul class=\"card-list\"><li>26 ülke hukuki çerçeve analizi</li><li>Karşılaştırmalı tablo ve rehber</li><li>Uluslararası iyi uygulama önerileri</li><li>OIC ve OSCE platformlarında lobi</li></ul></div><div class=\"card-foot\"><span class=\"card-lbl\">26 Ülke Rehberi</span><a href=\"/uluslararasi-sehit-gazi-haklari\" class=\"card-lnk\">Rehber →</a></div></div>\n      <div class=\"card\"><div class=\"card-st b\"></div><div class=\"card-body\"><div class=\"card-icon b\"><i class=\"fa fa-bullhorn\"></i></div><div class=\"card-title\">Lobi &amp; Farkındalık Çalışmaları</div><div class=\"card-desc\">TBMM komisyonları, uluslararası parlamentolar ve sivil toplum platformlarında şehit ve gazi haklarının savunuculuğu ve kamuoyu farkındalığı.</div><ul class=\"card-list\"><li>TBMM milletvekili brifingleri</li><li>BM insan hakları mekanizmaları</li><li>Avrupa Parlamentosu lobiciliği</li><li>Medya ve dijital farkındalık</li></ul></div><div class=\"card-foot\"><span class=\"card-lbl\">Lobi Ağı</span><a href=\"/iletisim\" class=\"card-lnk\">İletişim →</a></div></div>\n    </div>\n  </div>\n</div>\n\n\n<div class=\"sec\">\n  <div class=\"sec-w\">\n    <div class=\"sec-hd\">\n      <div class=\"badge r\">❓ Sık Sorulanlar</div>\n      <div class=\"sec-title\">Hukuki Danışmanlık SSS</div>\n    </div>\n    <div class=\"faq-list\">\n      <div class=\"faq-item\"><div class=\"faq-q\">Şehit yakını olarak hangi haklara sahibim?</div><div class=\"faq-a\">Şehit eş ve çocukları SGK'dan aylık maaş, sağlık yardımı, KYK burs önceliği, TOKİ konut önceliği ve çeşitli tazminatlardan yararlanma hakkına sahiptir. Detaylı bilgi için Şehit &amp; Gazi Hakları sayfamızı inceleyebilir ya da danışma hattımızı arayabilirsiniz.</div></div>\n      <div class=\"faq-item\"><div class=\"faq-q\">Gazi olarak protez hakkından nasıl yararlanabilirim?</div><div class=\"faq-a\">SGK kapsamındaki protez haklarınız için SGK'ya başvurabilirsiniz. SGK kapsam dışı kalan protez ve yardımcı cihazlar için vakfımızın protez destek programından ücretsiz yararlanabilirsiniz. Başvuru için iletişim formunuzu doldurun.</div></div>\n      <div class=\"faq-item\"><div class=\"faq-q\">Yurt dışında yaşıyorum, haklarımı nasıl kullanabilirim?</div><div class=\"faq-a\">26 ülkedeki gazi ve şehit ailesi hakları rehberimizi inceleyebilirsiniz. Türkiye'deki haklarınız için e-Devlet üzerinden veya vakfımızın danışmanlık hizmetiyle uzaktan destek alabilirsiniz. Bulunduğunuz ülkedeki Türk konsolosluğu aracılığıyla da işlemlerinizi yürütebilirsiniz.</div></div>\n      <div class=\"faq-item\"><div class=\"faq-q\">Vakfınızın danışmanlık hizmetleri ücretli mi?</div><div class=\"faq-a\">Hayır. Şehit ailelerine ve gazilere yönelik tüm danışmanlık hizmetlerimiz tamamen ücretsizdir. Vakfımız 501(c)(3) statüsünde kâr amacı gütmeyen uluslararası bir kuruluştur; yöneticilerimiz gönüllülük esasıyla hizmet vermektedir.</div></div>\n    </div>\n  </div>\n</div>\n\n<div class=\"ctaband\">\n  <div class=\"ctaband-w\">\n    <div class=\"ctaband-text\"><h3>Ücretsiz Hukuki Danışmanlık</h3><p>7/24 gazi danışma hattı: +90 312 963 07 95 · E-posta: vakif@vatankahramanlari.org</p></div>\n    <div class=\"ctabtns\">\n      <a href=\"/iletisim\" class=\"pbtn wh\">📞 Hemen Ara</a>\n      <a href=\"/sehit-gazi-haklari\" class=\"pbtn ol\">📋 Haklar Rehberi</a>\n    </div>\n  </div>\n</div>\n\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-hukuk-savunuculuk.php","importedAt":"2026-05-22T16:07:28.375Z"},{"id":"wp-template-insani-yardim","title":"İnsani Yardım","slug":"insani-yardim","bodyHtml":"<div style=\"max-width:100%;width:100%;padding:0;margin:0\">\r\n    <div class=\"wp-content-placeholder\">WordPress içerik alanı</div>\r\n    </div>\r\n    \r\n<style>:root{--r:#8C1A2E;--rd:#6E1222;--rl:rgba(140,26,46,.09);--g:#C9A84C;--gl:rgba(201,168,76,.1);--dk:#0D1117;--dk2:#1C2330;--wh:#FAFAF8;--gr:#F5F2ED;--bd:#E4E0D8;--t1:#1A1F28;--t2:#4A5568;--t3:#718096;--fn:'Nunito Sans',sans-serif;--fs:'Merriweather',serif;--w:1440px}\r\n*,*::before,*::after{box-sizing:border-box}\r\n\r\n\r\n.ph{width:100%;background:linear-gradient(150deg,var(--dk) 0%,var(--dk2) 55%,#18060a 100%);padding:72px 40px;position:relative;overflow:hidden;color:#fff}\r\n.ph-w{max-width:var(--w);margin:0 auto;display:grid;grid-template-columns:1.3fr 1fr;gap:60px;align-items:center;position:relative;z-index:1}\r\n.ph-ew{display:inline-flex;align-items:center;gap:7px;background:var(--gl);border:1px solid rgba(201,168,76,.3);color:var(--g);font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;padding:6px 14px;border-radius:20px;margin-bottom:18px}\r\n.ph-h1{font-family:var(--fs);font-size:clamp(1.8rem,3vw,2.8rem);font-weight:700;line-height:1.2;margin-bottom:14px}\r\n.ph-h1 em{color:var(--g);font-style:italic;display:block}\r\n.ph-desc{font-size:14px;color:rgba(255,255,255,.6);line-height:1.8;max-width:500px}\r\n\r\n\r\n.ph-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:rgba(255,255,255,.1);border-radius:12px;overflow:hidden}\r\n.ph-si{background:rgba(255,255,255,.04);padding:20px;text-align:center}\r\n.ph-sn{font-size:1.8rem;font-weight:800;color:var(--g);display:block}\r\n.ph-sl{font-size:9px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:rgba(255,255,255,.4)}\r\n\r\n\r\n.sec{width:100%;padding:60px 40px}.sec:nth-child(even){background:var(--gr)}\r\n.sec-w{max-width:var(--w);margin:0 auto}\r\n.sec-hd{margin-bottom:40px;border-bottom:2px solid var(--bd);padding-bottom:20px}\r\n.sec-title{font-family:var(--fs);font-size:1.6rem;font-weight:700;color:var(--t1)}\r\n\r\n\r\n.target-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:20px;margin-top:30px}\r\n.t-card{background:#fff;border:1px solid var(--bd);border-radius:12px;padding:30px 25px;text-align:center;transition:0.3s;position:relative;overflow:hidden}\r\n.t-card::before{content:'';position:absolute;top:0;left:0;right:0;height:4px;background:linear-gradient(90deg,var(--r),var(--g))}\r\n.t-card:hover{box-shadow:0 15px 35px rgba(0,0,0,0.07);transform:translateY(-5px)}\r\n.t-icon{font-size:2.5rem;margin-bottom:15px;display:block}\r\n.t-title{font-family:var(--fs);font-size:1.1rem;font-weight:700;color:var(--t1);margin-bottom:10px}\r\n.t-desc{font-size:12px;color:var(--t2);line-height:1.7}\r\n\r\n\r\n.infobox{background:var(--rl);border-left:4px solid var(--r);padding:25px;border-radius:0 8px 8px 0;margin-top:40px}\r\n.infobox strong{display:block;color:var(--rd);margin-bottom:10px;font-size:14px;text-transform:uppercase;letter-spacing:1px}\r\n.infobox p{font-size:13px;color:var(--t2);line-height:1.8;margin:0}\r\n\r\n\r\n.grid{display:grid;gap:20px}.g3{grid-template-columns:repeat(3,1fr)}\r\n.card{background:#fff;border:1px solid var(--bd);border-radius:12px;padding:30px;transition:0.3s;display:flex;flex-direction:column}\r\n.card:hover{box-shadow:0 12px 30px rgba(0,0,0,0.08)}\r\n.card-icon{width:50px;height:50px;background:var(--rl);color:var(--r);border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:1.5rem;margin-bottom:20px}\r\n.card-title{font-family:var(--fs);font-size:1.2rem;font-weight:700;color:var(--t1);margin-bottom:12px}\r\n.card-desc{font-size:13px;color:var(--t2);line-height:1.7;margin-bottom:20px;flex:1}\r\n.card-list{list-style:none;padding:0;margin:0}\r\n.card-list li{font-size:11.5px;color:var(--t2);display:flex;gap:10px;margin-bottom:8px;align-items:flex-start}\r\n.card-list li::before{content:\"●\";color:var(--g);font-size:10px;margin-top:3px}\r\n\r\n@media(max-width:860px){.ph-w,.g3,.target-grid{grid-template-columns:1fr}.sec,.ph{padding:40px 20px}}</style>\r\n\r\n<div class=\"pw\">\r\n    <div class=\"ph\">\r\n        <div class=\"ph-w\">\r\n            <div>\r\n                <div class=\"ph-ew\">🔴 Vatan Kahramanları Yardımlaşma</div>\r\n                <h1 class=\"ph-h1\">Vatan Kahramanları<em>İnsani Destek Ağı</em></h1>\r\n                <p class=\"ph-desc\">\r\n                    Vatan Kahramanları Derneği ve Vakfı olarak; gazi ve şehit yakınlarımızın tıbbi ihtiyaçlarından rehabilitasyon süreçlerine kadar her an yanlarındayız. \r\n                    <strong>Şeffaf bağış yönetimi</strong> ve <strong>uluslararası statümüzle</strong> vefayı hizmete dönüştürüyoruz.\r\n                </p>\r\n            </div>\r\n            <div class=\"ph-stats\">\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">%100</span><span class=\"ph-sl\">Şeffaflık</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">5</span><span class=\"ph-sl\">Kıta</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">14</span><span class=\"ph-sl\">Ülke</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">501c3</span><span class=\"ph-sl\">Akreditasyon</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">🛡️</span><span class=\"ph-sl\">Gazi Desteği</span></div>\r\n                <div class=\"ph-si\"><span class=\"ph-sn\">∞</span><span class=\"ph-sl\">Milli Vefa</span></div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"sec\">\r\n        <div class=\"sec-w\">\r\n            <div class=\"sec-hd\">\r\n                <h2 class=\"sec-title\">Medikal ve Sosyal Destek Programları</h2>\r\n            </div>\r\n            <div class=\"grid g3\">\r\n                <div class=\"card\">\r\n                    <div class=\"card-icon\">🦾</div>\r\n                    <div class=\"card-title\">Protez ve Ortopedi</div>\r\n                    <p class=\"card-desc\">SGK kapsamı dışında kalan yüksek teknolojili protezlerin temini ve uzun vadeli bakım süreçlerini vakıf imkanlarımızla karşılıyoruz.</p>\r\n                    <ul class=\"card-list\">\r\n                        <li>Biyonik el ve ayak protezi desteği</li>\r\n                        <li>Yurt dışı medikal partner ağı</li>\r\n                        <li>Yıllık bakım ve parça garantisi</li>\r\n                    </ul>\r\n                </div>\r\n\r\n                <div class=\"card\">\r\n                    <div class=\"card-icon\">🧠</div>\r\n                    <div class=\"card-title\">Psikolojik Rehabilitasyon</div>\r\n                    <p class=\"card-desc\">Travma sonrası süreçlerde gazi ve ailelerine yönelik uzman klinik psikologlarımızla profesyonel terapi desteği sunuyoruz.</p>\r\n                    <ul class=\"card-list\">\r\n                        <li>Bireysel ve grup terapileri</li>\r\n                        <li>Şehit çocukları için pedagojik destek</li>\r\n                        <li>7/24 kriz hattı ve danışmanlık</li>\r\n                    </ul>\r\n                </div>\r\n\r\n                <div class=\"card\">\r\n                    <div class=\"card-icon\">📦</div>\r\n                    <div class=\"card-title\">Acil İnsani Yardım</div>\r\n                    <p class=\"card-desc\">Afet durumlarında ve kriz bölgelerinde; AFAD, Kızılay ve diğer kuruluşlar ile koordineli olarak gıda, barınma ve sağlık kiti ulaştırıyoruz.</p>\r\n                    <ul class=\"card-list\">\r\n                        <li>Saha operasyon lojistiği</li>\r\n                        <li>Türk Dünyası yardım koridoru</li>\r\n                        <li>Medikal cihaz ve ilaç yardımı</li>\r\n                    </ul>\r\n                </div>\r\n            </div>\r\n            \r\n            <div class=\"infobox\">\r\n                <strong>💰 Hesap Verebilirlik ve Şeffaflık</strong>\r\n                <p>Vatan Kahramanları Vakfı, 501(c)(3) statüsünde uluslararası kamu yararına çalışan bir kuruluştur. Bağışlarınızın her kuruşu doğrudan medikal cihaz temini ve rehabilitasyon hizmetlerine aktarılır. Faaliyet raporlarımız periyodik olarak kamuoyuyla paylaşılmaktadır.</p>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"sec\">\r\n        <div class=\"sec-w\">\r\n            <div class=\"sec-hd\">\r\n                <h2 class=\"sec-title\">Kimlerin Yanındayız?</h2>\r\n            </div>\r\n            <div class=\"target-grid\">\r\n                <div class=\"t-card\">\r\n                    <span class=\"t-icon\">🇹🇷</span>\r\n                    <div class=\"t-title\">Türk Dünyası Gazileri</div>\r\n                    <p class=\"t-desc\">Türkiye, Azerbaycan ve tüm Türk devletlerindeki kahramanlarımıza protez ve rehabilitasyon önceliği sağlıyoruz.</p>\r\n                </div>\r\n                <div class=\"t-card\">\r\n                    <span class=\"t-icon\">🇽🇰</span>\r\n                    <div class=\"t-title\">Osmanlı Mirası Coğrafyalar</div>\r\n                    <p class=\"t-desc\">Bosna ve Kosova gibi kardeş coğrafyalardaki savaş ve terör mağduru ailelere insani yardım köprüsü kuruyoruz.</p>\r\n                </div>\r\n                <div class=\"t-card\">\r\n                    <span class=\"t-icon\">♿</span>\r\n                    <div class=\"t-title\">İhtiyaç Sahibi Engelliler</div>\r\n                    <p class=\"t-desc\">Şehit ve gazi yakınlığı dışında kalan, maddi imkansızlıklar nedeniyle medikal cihaz erişimi olmayan vatandaşlarımıza destek oluyoruz.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div style=\"background:var(--r); padding:60px 20px; text-align:center; color:#fff\">\r\n        <div class=\"sec-w\">\r\n            <h3 style=\"font-family:var(--fs); font-size:1.6rem; margin-bottom:15px\">Bir Kahramanın Hayatına Dokunun</h3>\r\n            <p style=\"margin-bottom:30px; opacity:0.85; max-width:700px; margin-left:auto; margin-right:auto\">Bağışlarınız Stripe ve 501(c)(3) güvencesiyle doğrudan ihtiyaç sahiplerine ulaşır.</p>\r\n            <div style=\"display:flex; justify-content:center; gap:20px; flex-wrap:wrap\">\r\n                <a href=\"/bagis\" style=\"background:var(--wh); color:var(--r); padding:14px 40px; border-radius:6px; font-weight:700; text-decoration:none\">💝 Şimdi Bağış Yap</a>\r\n                <a href=\"/iletisim\" style=\"background:transparent; color:#fff; border:2px solid rgba(255,255,255,0.4); padding:14px 40px; border-radius:6px; font-weight:700; text-decoration:none\">📩 Yardım Talebi Oluştur</a>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-insani-yardim.php","importedAt":"2026-05-22T16:07:28.376Z"},{"id":"wp-template-isbirligi","title":"İşbirliği Alanları","slug":"isbirligi","bodyHtml":"<div style=\"max-width:100%;width:100%;padding:0;margin:0\">\r\n    <div class=\"wp-content-placeholder\">WordPress içerik alanı</div>\r\n    </div>\r\n    \r\n\r\n<style>:root{--r:#8C1A2E;--rd:#6E1222;--rl:rgba(140,26,46,.09);--g:#C9A84C;--gl:rgba(201,168,76,.1);--dk:#0D1117;--dk2:#1C2330;--wh:#FAFAF8;--gr:#F5F2ED;--bd:#E4E0D8;--t1:#1A1F28;--t2:#4A5568;--t3:#718096;--fn:'Nunito Sans',sans-serif;--fs:'Merriweather',serif;--w:1440px}\r\n\r\n.ib-wrap{font-family:var(--fn);background:var(--wh);color:var(--t1)}\r\n\r\n\r\n.ib-hero{width:100%;background:linear-gradient(155deg,var(--dk) 0%,var(--dk2) 50%,#0a1a12 100%);padding:80px 40px;position:relative;overflow:hidden;color:#fff}\r\n.ib-hero::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse 60% 70% at 80% 50%,rgba(140,26,46,.2) 0%,transparent 70%)}\r\n.ib-hero-w{max-width:var(--w);margin:0 auto;display:grid;grid-template-columns:1.3fr 1fr;gap:60px;align-items:center;position:relative;z-index:1}\r\n.ib-eyebrow{display:inline-flex;align-items:center;gap:8px;background:rgba(201,168,76,.15);border:1px solid rgba(201,168,76,.4);color:var(--g);font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;padding:7px 16px;border-radius:30px;margin-bottom:20px}\r\n.ib-hero h1{font-family:var(--fs);font-size:clamp(2rem,3.5vw,3rem);font-weight:700;line-height:1.2;margin-bottom:18px}\r\n.ib-hero h1 em{color:var(--g);font-style:italic;display:block}\r\n.ib-hero-desc{font-size:16px;color:rgba(255,255,255,0.6);line-height:1.8;max-width:550px}\r\n\r\n\r\n.ib-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:rgba(255,255,255,0.1);border-radius:12px;overflow:hidden;box-shadow:0 20px 40px rgba(0,0,0,0.3)}\r\n.ib-si{background:rgba(255,255,255,0.05);padding:25px 15px;text-align:center;transition:0.3s}\r\n.ib-si:hover{background:rgba(255,255,255,0.1)}\r\n.ib-sn{font-size:1.8rem;font-weight:800;color:var(--g);display:block;margin-bottom:5px}\r\n.ib-sl{font-size:9px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:rgba(255,255,255,0.4)}\r\n\r\n\r\n.ib-sec{width:100%;padding:80px 40px}.ib-sec:nth-child(even){background:var(--gr)}\r\n.ib-sec-w{max-width:var(--w);margin:0 auto}\r\n.ib-sec-hd{margin-bottom:50px;display:flex;justify-content:space-between;align-items:flex-end;gap:30px;border-bottom:1px solid var(--bd);padding-bottom:25px}\r\n.ib-sec-badge{display:inline-flex;padding:5px 15px;border-radius:20px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1px;margin-bottom:10px}\r\n.ib-sec-badge.red{background:var(--rl);color:var(--r)}\r\n.ib-sec-badge.blue{background:#EFF6FF;color:#1D4ED8}\r\n.ib-sec-badge.gold{background:var(--gl);color:#7a5a00}\r\n.ib-sec-title{font-family:var(--fs);font-size:2rem;color:var(--t1);font-weight:700}\r\n.ib-sec-sub{font-size:14px;color:var(--t3);max-width:600px;line-height:1.6}\r\n\r\n\r\n.ib-grid{display:grid;gap:25px}\r\n.ib-g3{grid-template-columns:repeat(3,1fr)}\r\n.ib-g2{grid-template-columns:repeat(2,1fr)}\r\n.ib-card{background:#fff;border:1px solid var(--bd);border-radius:12px;padding:40px 30px;transition:0.3s;position:relative;display:flex;flex-direction:column}\r\n.ib-card:hover{transform:translateY(-5px);box-shadow:0 15px 35px rgba(0,0,0,0.07)}\r\n.ib-card-icon{width:60px;height:60px;background:var(--gr);border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:1.8rem;margin-bottom:25px;color:var(--r)}\r\n.ib-card-title{font-family:var(--fs);font-size:1.2rem;font-weight:700;margin-bottom:15px;color:var(--t1)}\r\n.ib-card-desc{font-size:13.5px;color:var(--t2);line-height:1.75;margin-bottom:20px;flex:1}\r\n.ib-card-tags{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:20px}\r\n.ib-tag{font-size:10px;font-weight:700;padding:4px 10px;background:var(--wh);border:1px solid var(--bd);border-radius:4px;color:var(--t3)}\r\n.ib-card-footer{padding-top:20px;border-top:1px solid var(--bd);display:flex;justify-content:space-between;align-items:center}\r\n.ib-card-link{font-size:11px;font-weight:800;color:var(--r);text-decoration:none;text-transform:uppercase;letter-spacing:1px}\r\n\r\n@media(max-width:1100px){.ib-g3{grid-template-columns:repeat(2,1fr)}.ib-hero-w{grid-template-columns:1fr}}\r\n@media(max-width:768px){.ib-g3,.ib-g2{grid-template-columns:1fr}.ib-sec-hd{flex-direction:column;align-items:flex-start}.ib-sec{padding:60px 20px}}</style>\r\n\r\n<div class=\"ib-wrap\">\r\n\r\n    <div class=\"ib-hero\">\r\n        <div class=\"ib-hero-w\">\r\n            <div>\r\n                <div class=\"ib-eyebrow\">🌐 Global İşbirliği Alanları</div>\r\n                <h1>Vatan Kahramanları İçin<em>Sürdürülebilir Gelecek</em></h1>\r\n                <p class=\"ib-hero-desc\">\r\n                    Derneğimiz, Vatan Kahramanları Vakfı ve Dünya Sağlık Vakfı ile birlikte ; gazi desteğinden eğitime, insani yardımdan kültürel diplomasiye kadar <strong>4 ana eksende</strong> küresel paydaşlarımızla projeler yürütüyoruz.\r\n                </p>\r\n            </div>\r\n            <div class=\"ib-stats\">\r\n                <div class=\"ib-si\"><span class=\"ib-sn\">501c3</span><span class=\"ib-sl\">Global Statü</span></div>\r\n                <div class=\"ib-si\"><span class=\"ib-sn\">13</span><span class=\"ib-sl\">Ülke Ofisi</span></div>\r\n                <div class=\"ib-si\"><span class=\"ib-sn\">40+</span><span class=\"ib-sl\">Kurumsal Ortak</span></div>\r\n                <div class=\"ib-si\"><span class=\"ib-sn\">∞</span><span class=\"ib-sl\">Vefa Borcu</span></div>\r\n                <div class=\"ib-si\"><span class=\"ib-sn\">%100</span><span class=\"ib-sl\">Şeffaflık</span></div>\r\n                <div class=\"ib-si\"><span class=\"ib-sn\">5</span><span class=\"ib-sl\">Kıta Etki</span></div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"ib-sec\">\r\n        <div class=\"ib-sec-w\">\r\n            <div class=\"ib-sec-hd\">\r\n                <div>\r\n                    <div class=\"ib-sec-badge red\">🎖️ Öncelikli Odak</div>\r\n                    <h2 class=\"ib-sec-title\">Gazi Desteği & İnsani Yardım</h2>\r\n                </div>\r\n                <p class=\"ib-sec-sub\">Dünya genelindeki Türk dünyası kahramanları ve savaş mağdurları için kapsamlı rehabilitasyon ve hayatı kolaylaştırma programları.</p>\r\n            </div>\r\n            \r\n            <div class=\"ib-grid ib-g3\">\r\n                <div class=\"ib-card\">\r\n                    <div class=\"ib-card-icon\">🏥</div>\r\n                    <h3 class=\"ib-card-title\">Protez & Medikal Destek</h3>\r\n                    <p class=\"ib-card-desc\">Dünya Sağlık Vakfı (DSV) protokolleri ile gazilerimiz için en ileri teknoloji protez ve rehabilitasyon süreçlerini yönetiyoruz.</p>\r\n                    <div class=\"ib-card-tags\"><span class=\"ib-tag\">Medikal</span><span class=\"ib-tag\">Rehabilitasyon</span></div>\r\n                    <div class=\"ib-card-footer\">\r\n                        <span style=\"font-size:10px; color:var(--t3)\">Global Sağlık Ağı</span>\r\n                        <a href=\"/bagis\" class=\"ib-card-link\">Destek Ol →</a>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"ib-card\">\r\n                    <div class=\"ib-card-icon\">🛡️</div>\r\n                    <h3 class=\"ib-card-title\">Psikososyal Güçlendirme</h3>\r\n                    <p class=\"ib-card-desc\">Savaş ve terör mağduru gazilerimizin toplumsal hayata tam uyumu için profesyonel danışmanlık ve grup terapileri sunuyoruz.</p>\r\n                    <div class=\"ib-card-tags\"><span class=\"ib-tag\">Sosyal Uyum</span><span class=\"ib-tag\">Terapi</span></div>\r\n                    <div class=\"ib-card-footer\">\r\n                        <span style=\"font-size:10px; color:var(--t3)\">Klinik Destek</span>\r\n                        <a href=\"/sehit-gazi-haklari\" class=\"ib-card-link\">İncele →</a>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"ib-card\">\r\n                    <div class=\"ib-card-icon\">📦</div>\r\n                    <h3 class=\"ib-card-title\">Acil Lojistik & Yardım</h3>\r\n                    <p class=\"ib-card-desc\">Çatışma bölgelerindeki sivil mağdurlar ve terör mağdurları için gıda, barınma ve temel ihtiyaç lojistiği sağlıyoruz.</p>\r\n                    <div class=\"ib-card-tags\"><span class=\"ib-tag\">Hızlı Müdahale</span><span class=\"ib-tag\">Lojistik</span></div>\r\n                    <div class=\"ib-card-footer\">\r\n                        <span style=\"font-size:10px; color:var(--t3)\">13 Ülke Hattı</span>\r\n                        <a href=\"/bagis\" class=\"ib-card-link\">Bağış Yap →</a>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"ib-sec\">\r\n        <div class=\"ib-sec-w\">\r\n            <div class=\"ib-sec-hd\">\r\n                <div>\r\n                    <div class=\"ib-sec-badge blue\">🎓 Akademik Gelecek</div>\r\n                    <h2 class=\"ib-sec-title\">Eğitim & Burs Programları</h2>\r\n                </div>\r\n                <p class=\"ib-sec-sub\">Vatan kahramanlarımızın emaneti olan evlatlarımıza uluslararası standartlarda eğitim ve gelişim fırsatları.</p>\r\n            </div>\r\n            \r\n            <div class=\"ib-grid ib-g2\">\r\n                <div class=\"ib-card\">\r\n                    <div class=\"ib-card-icon\">🌍</div>\r\n                    <h3 class=\"ib-card-title\">Uluslararası Değişim Programları</h3>\r\n                    <p class=\"ib-card-desc\">TDT Orhun Değişim Programı ve partner üniversitelerimiz aracılığıyla öğrencilerimize yurt dışında eğitim ve staj imkanları sunuyoruz.</p>\r\n                    <div class=\"ib-card-footer\">\r\n                        <span style=\"font-size:10px; color:var(--t3)\">Türk Akademisi Ortaklığı</span>\r\n                        <a href=\"/iletisim\" class=\"ib-card-link\">Başvuru Koşulları →</a>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"ib-card\">\r\n                    <div class=\"ib-card-icon\">🎓</div>\r\n                    <h3 class=\"ib-card-title\">Akademik Başarı Bursları</h3>\r\n                    <p class=\"ib-card-desc\">Lisans ve lisansüstü düzeyde eğitim gören şehit ve gazi yakınlarına karşılıksız eğitim bursu ve kariyer mentorluğu sağlıyoruz.</p>\r\n                    <div class=\"ib-card-footer\">\r\n                        <span style=\"font-size:10px; color:var(--t3)\">Kariyer Mentorluğu</span>\r\n                        <a href=\"/burs\" class=\"ib-card-link\">Burs Bilgi →</a>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"ib-sec\">\r\n        <div class=\"ib-sec-w\">\r\n            <div class=\"ib-sec-hd\">\r\n                <div>\r\n                    <div class=\"ib-sec-badge gold\">🏛️ Kültürel Miras</div>\r\n                    <h2 class=\"ib-sec-title\">Etkinlikler & Tanıtım</h2>\r\n                </div>\r\n                <p class=\"ib-sec-sub\">Ortak tarih ve kültür bilinciyle Türk dünyasının kahramanlık mirasını geleceğe taşıyoruz.</p>\r\n            </div>\r\n            \r\n            <div class=\"ib-grid ib-g3\">\r\n                <div class=\"ib-card\">\r\n                    <div class=\"ib-card-icon\">🤝</div>\r\n                    <h3 class=\"ib-card-title\">Uluslararası Kurultaylar</h3>\r\n                    <p class=\"ib-card-desc\">Gazi dernekleri ve uluslararası STK temsilcilerini bir araya getiren yıllık strateji ve dayanışma toplantıları.</p>\r\n                </div>\r\n\r\n                <div class=\"ib-card\">\r\n                    <div class=\"ib-card-icon\">📜</div>\r\n                    <h3 class=\"ib-card-title\">E-Vatan Dijital Arşiv</h3>\r\n                    <p class=\"ib-card-desc\">Kahramanlarımızın biyografilerini, tarihi belgeleri ve kültürel yayınları dijital dünyada ölümsüzleştiriyoruz.</p>\r\n                </div>\r\n\r\n                <div class=\"ib-card\">\r\n                    <div class=\"ib-card-icon\">🌳</div>\r\n                    <h3 class=\"ib-card-title\">Yeşil Vatan Projeleri</h3>\r\n                    <p class=\"ib-card-desc\">OGM işbirliğiyle şehitlerimizin adını taşıyan hatıra ormanları ve doğayı şehitlerimizin vefasıyla yeşertmeyi hedefliyoruz.</p>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div style=\"background:var(--r); padding:60px 20px; text-align:center; color:#fff\">\r\n        <div class=\"ib-sec-w\">\r\n            <h3 style=\"font-family:var(--fs); font-size:1.8rem; margin-bottom:15px\">Paydaşımız Olun</h3>\r\n            <p style=\"margin-bottom:30px; opacity:0.8; max-width:700px; margin:0 auto 30px\">\r\n                Vakfımızla proje bazlı işbirliği yapmak, kurumsal destekçi olmak veya temsilcilik yürütmek için profesyonel ekibimizle görüşebilirsiniz.\r\n            </p>\r\n            <div style=\"display:flex; justify-content:center; gap:15px; flex-wrap:wrap\">\r\n                <a href=\"/iletisim\" style=\"background:#fff; color:var(--r); padding:14px 40px; border-radius:6px; font-weight:800; text-decoration:none\">İletişime Geç</a>\r\n                <a href=\"/category/dernegimiz/\" style=\"background:transparent; color:#fff; border:2px solid #fff; padding:14px 40px; border-radius:6px; font-weight:800; text-decoration:none\">Kurumsal Yapımız</a>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n</div>","enabled":true,"fullWidth":true,"importSource":"wordpress-template","sourceName":"page-isbirligi.php","importedAt":"2026-05-22T16:07:28.377Z"},{"id":"wp-template-kurumlar","title":"İlişkili Kurumlar (Tam Eksiksiz Premium Rehber)","slug":"kurumlar","bodyHtml":"<div class=\"wp-content-placeholder\">WordPress içerik alanı</div>\n\n\n<style>600;700;800&family=Playfair+Display:wght@700;900&family=Inter:wght@300;400;500;600&display=swap');\n\n:root {\n    --v-red: #8C1A2E; --v-red-d: #6E1222; --v-gold: #C9A84C;\n    --v-dark: #0D1117; --v-dark-2: #1C2330; --v-text: #1A1F28;\n    --v-gray: #F5F2ED; --v-border: #E4E0D8; --v-white: #FFFFFF;\n    --shadow-p: 0 15px 35px rgba(0,0,0,0.1);\n}\n\n.kurum-portal { font-family: 'Inter', sans-serif; background: #FAFAFA; color: var(--v-text); padding-bottom: 100px; }\n\n\n.kurum-hero {\n    background: linear-gradient(150deg, var(--v-dark) 0%, var(--v-dark-2) 55%, #18060a 100%);\n    padding: 100px 24px; text-align: center; color: #fff; position: relative; border-bottom: 5px solid var(--v-gold);\n}\n.kurum-hero::before { content: ''; position: absolute; inset: 0; background: url('https://www.transparenttextures.com/patterns/carbon-fibre.png'); opacity: 0.1; }\n.kurum-hero h1 { font-family: 'Playfair Display', serif; font-size: clamp(2.5rem, 6vw, 3.8rem); margin-bottom: 20px; font-weight: 900; position: relative; }\n.kurum-hero p { max-width: 800px; margin: 0 auto; font-size: 1.2rem; opacity: 0.8; font-weight: 300; position: relative; }\n\n\n.kurum-controls {\n    position: sticky; top: 0; z-index: 1000; background: rgba(255,255,255,0.98);\n    backdrop-filter: blur(10px); border-bottom: 1px solid var(--v-border); box-shadow: var(--shadow-p);\n    padding: 20px 24px;\n}\n.controls-inner { max-width: 1400px; margin: 0 auto; display: flex; align-items: center; justify-content: space-between; gap: 30px; flex-wrap: wrap; }\n\n.search-wrap { flex: 1; min-width: 320px; position: relative; }\n.search-wrap input {\n    width: 100%; padding: 16px 55px 16px 25px; border-radius: 100px; border: 2px solid var(--v-border);\n    font-size: 15px; font-weight: 500; outline: none; transition: 0.4s; background: var(--v-gray);\n}\n.search-wrap input:focus { border-color: var(--v-red); background: #fff; box-shadow: 0 0 0 5px rgba(140, 26, 46, 0.1); }\n.search-wrap i { position: absolute; right: 25px; top: 50%; transform: translateY(-50%); color: var(--v-red); font-size: 18px; }\n\n.filter-pills { display: flex; gap: 12px; flex-wrap: wrap; }\n.f-pill {\n    padding: 12px 24px; border-radius: 100px; border: 1.5px solid var(--v-border);\n    background: #fff; font-size: 12px; font-weight: 800; cursor: pointer;\n    transition: 0.3s; text-transform: uppercase; letter-spacing: 1px; color: var(--v-text);\n}\n.f-pill.active, .f-pill:hover { background: var(--v-red); color: #fff; border-color: var(--v-red); transform: translateY(-2px); }\n\n\n.kurum-container { max-width: 1400px; margin: 60px auto; padding: 0 24px; }\n.kurum-sec-head {\n    display: flex; align-items: center; justify-content: space-between;\n    margin-bottom: 35px; border-left: 6px solid var(--v-red); padding-left: 20px;\n}\n.kurum-sec-head h2 { font-family: 'Montserrat', sans-serif; font-size: 1.6rem; font-weight: 800; color: var(--v-dark); margin: 0; }\n.kurum-sec-head .count { background: var(--v-gold); color: #000; padding: 6px 16px; border-radius: 50px; font-size: 12px; font-weight: 900; }\n\n.kurum-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(330px, 1fr)); gap: 20px; margin-bottom: 80px; }\n\n\n.kurum-card {\n    background: #fff; border: 1px solid var(--v-border); border-radius: 18px;\n    padding: 30px 25px; display: flex; align-items: flex-start; gap: 20px;\n    text-decoration: none !important; transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);\n    position: relative; overflow: hidden;\n}\n.kurum-card::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 4px; background: var(--v-red); transition: 0.4s; }\n.kurum-card:hover { transform: translateY(-8px); border-color: transparent; box-shadow: var(--shadow-p); }\n.kurum-card:hover::after { width: 100%; }\n\n.kurum-emblem {\n    width: 65px; height: 65px; border-radius: 15px; background: var(--v-gray);\n    display: flex; align-items: center; justify-content: center; font-size: 2rem; flex-shrink: 0;\n    transition: 0.4s; border: 1px solid rgba(0,0,0,0.05);\n}\n.kurum-card:hover .kurum-emblem { background: var(--v-red); color: #fff; transform: scale(1.1) rotate(-5deg); }\n\n.kurum-info { flex-grow: 1; }\n.kurum-name { display: block; font-weight: 800; color: var(--v-dark); font-size: 14px; line-height: 1.4; margin-bottom: 6px; transition: 0.3s; }\n.kurum-desc { display: block; font-size: 12px; color: #718096; font-weight: 500; }\n.kurum-card:hover .kurum-name { color: var(--v-red); }\n\n.k-link-icon { align-self: center; font-size: 14px; color: var(--v-border); transition: 0.3s; }\n.kurum-card:hover .k-link-icon { color: var(--v-gold); transform: translateX(5px); }\n\n\n#no-result { display: none; text-align: center; padding: 100px 20px; background: #fff; border-radius: 30px; border: 2px dashed var(--v-border); }\n#no-result i { font-size: 60px; color: var(--v-red); margin-bottom: 20px; opacity: 0.3; }\n\n@media (max-width: 768px) { .kurum-grid { grid-template-columns: 1fr; } .controls-inner { flex-direction: column; } .search-wrap { width: 100%; } }</style>\n\n<div class=\"kurum-portal\">\n    <section class=\"kurum-hero\">\n        <div class=\"kurum-container\">\n            <div style=\"font-size:12px; letter-spacing:4px; color:var(--v-gold); font-weight:800; margin-bottom:15px; text-transform:uppercase;\">Stratejik Çözüm Ortakları</div>\n            <h1>İlişkili Kurumlar Portalı</h1>\n            <p>Türkiye Cumhuriyeti'nin köklü devlet yapıları, Türk Dünyası'nın birleştirici kurumları ve stratejik ortaklarımız.</p>\n        </div>\n    </section>\n\n    <div class=\"kurum-controls\">\n        <div class=\"controls-inner\">\n            <div class=\"search-wrap\">\n                <input type=\"text\" id=\"kinp\" placeholder=\"Bakanlık, kurum adı veya anahtar kelime...\">\n                <i class=\"fa-solid fa-magnifying-glass\"></i>\n            </div>\n            <div class=\"filter-pills\">\n                <button class=\"f-pill active\" type=\"button\">📋 Tüm Liste</button>\n                <button class=\"f-pill\" type=\"button\">⚔️ Askeri</button>\n                <button class=\"f-pill\" type=\"button\">🏛️ Devlet</button>\n                <button class=\"f-pill\" type=\"button\">🤝 Sivil</button>\n                <button class=\"f-pill\" type=\"button\">🌐 Uluslararası</button>\n            </div>\n        </div>\n    </div>\n\n    <div class=\"kurum-container\">\n        \n        <div class=\"kurum-section\" data-cat=\"askeri\">\n            <div class=\"kurum-sec-head\">\n                <h2>Askeri Kurumlar</h2>\n                <span class=\"count\">7 KURUM</span>\n            </div>\n            <div class=\"kurum-grid\">\n                <a href=\"https://www.msb.gov.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Genelkurmay Başkanlığı TSK\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🪖</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Genelkurmay Başkanlığı</span><span class=\"kurum-desc\">msb.gov.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.kkk.tsk.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Kara Kuvvetleri Komutanlığı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🛡️</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Kara Kuvvetleri Komutanlığı</span><span class=\"kurum-desc\">kkk.tsk.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.hvkk.tsk.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Hava Kuvvetleri Komutanlığı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">✈️</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Hava Kuvvetleri Komutanlığı</span><span class=\"kurum-desc\">hvkk.tsk.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.dzkk.tsk.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Deniz Kuvvetleri Komutanlığı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">⚓</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Deniz Kuvvetleri Komutanlığı</span><span class=\"kurum-desc\">dzkk.tsk.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.jandarma.gov.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Jandarma Genel Komutanlığı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🦅</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Jandarma Genel Komutanlığı</span><span class=\"kurum-desc\">jandarma.gov.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.egm.gov.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Emniyet Genel Müdürlüğü Polis\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">👮</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Emniyet Genel Müdürlüğü</span><span class=\"kurum-desc\">egm.gov.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.msb.gov.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Milli Savunma Bakanlığı MSB\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">⭐</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Milli Savunma Bakanlığı</span><span class=\"kurum-desc\">msb.gov.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n            </div>\n        </div>\n\n        <div class=\"kurum-section\" data-cat=\"devlet\">\n            <div class=\"kurum-sec-head\