icon\"></i>\n                </a>\n                <a href=\"https://www.kyk.gov.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"KYK Kredi Yurtlar Kurumu burs yurt\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🎒</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">KYK</span><span class=\"kurum-desc\">kyk.gov.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.diyanet.gov.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Diyanet İşleri Başkanlığı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">☪️</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Diyanet İşleri Başkanlığı</span><span class=\"kurum-desc\">diyanet.gov.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.tika.gov.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"TİKA Türk İşbirliği Koordinasyon Ajansı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🌐</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">TİKA</span><span class=\"kurum-desc\">tika.gov.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.ytb.gov.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"YTB Yurtdışı Türkler Akraba Topluluklar\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🌍</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">YTB</span><span class=\"kurum-desc\">ytb.gov.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n            </div>\n        </div>\n\n        <div class=\"kurum-section\" data-cat=\"sivil\">\n            <div class=\"kurum-sec-head\">\n                <h2>Sivil Kuruluşlar</h2>\n                <span class=\"count\">10 KURULUŞ</span>\n            </div>\n            <div class=\"kurum-grid\">\n                <a href=\"https://vatankahramanlari.org/\" target=\"_blank\" class=\"kurum-card\" data-n=\"Vatan Kahramanları Derneği\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🎖️</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Vatan Kahramanları Derneği</span><span class=\"kurum-desc\">vatankahramanlari.org.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://tukav.org/tr/\" target=\"_blank\" class=\"kurum-card\" data-n=\"TürkAta Vakfı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">⚔️</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">TürkAta Vakfı</span><span class=\"kurum-desc\">turkatav.org</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.sehitgazi.org.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"TÜRK ŞEHİTLİKLERİ TANITIM MERKEZİ\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🏛️</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Türk Şehitlikleri Tanıtım Merkezi</span><span class=\"kurum-desc\">sehitgazi.org.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://yesilvatan.gen.tr\" target=\"_blank\" class=\"kurum-card\" data-n=\"Yeşil Vatan Türkiye Ağaçlandırma Merkezi\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🌳</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Yeşil Vatan Türkiye Ağaçlandırma Merkezi</span><span class=\"kurum-desc\">yesilvatan.gen.tr</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://dunyasaglik.org\" target=\"_blank\" class=\"kurum-card\" data-n=\"Dünya Sağlık Vakfı DSV\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🩺</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">DSV Dünya Sağlık Vakfı</span><span class=\"kurum-desc\">dunyasaglik.org</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://www.engellispor\" target=\"_blank\" class=\"kurum-card\" data-n=\"Engelli Sporları Vakfı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🏹</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Engelli Sporları Vakfı</span><span class=\"kurum-desc\">engellispor.org</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://turkiye.li\" target=\"_blank\" class=\"kurum-card\" data-n=\"Türkiye Kütüphanesi\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">📖</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Türkiye Kütüphanesi</span><span class=\"kurum-desc\">turkiye.li</span></div>\n                    <i class=\"fa-solid fa-arrow-up-right-from-square k-link-icon\"></i>\n                </a>\n                <a href=\"https://btvakfi.org\" target=\"_blank\" class=\"kurum-card\" data-n=\"Bilgi Teknolojileri Vakfı\" rel=\"noopener noreferrer\">\n                    <div class=\"kurum-emblem\">🎓</div>\n                    <div class=\"kurum-info\"><span class=\"kurum-name\">Bilgi Teknolojileri Vakfı</sp